-- Run this in the Supabase SQL editor as a privileged user.
BEGIN;

TRUNCATE TABLE faculty_master;

INSERT INTO faculty_master (id, name, email, designation, department, photo_url, education, phone, office, website, profile, research_interests, teaching_interests, labs, publications, last_scraped, created_at, updated_at, biography) VALUES
  ('162', 'A V Subramanyam', 'subramanyam@iiitd.ac.in', 'Professor (ECE, CSE)', 'ECE, CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/subramanyam.jpg', 'Ph.D. (2012), Nanyang Technological University, Singapore', '+91 011-26907437', 'B-405 (R&D Block)', 'https://vcg.iiitd.edu.in/', 'https://iiitd.ac.in/subramanyam', '["Multimedia and Vision","Machine Learning"]', '["Statistical Machine Learning","Digital Image Processing","Digital Signal Processing","Signals and Systems","Multimedia Security"]', '["Infosys Centre for Artificial Intelligence (CAI)","Visual Conception Group"]', '[]', '2026-06-23 12:51:03.753', '2026-06-23 12:51:06.066962', '2026-06-23 12:51:03.755', 'A V Subramanyam is a Professor in the Departments of Electronics and Communications Engineering (ECE) and Computer Science and Engineering (CSE) at IIIT-Delhi. He received his PhD from Nanyang Technological University, Singapore in 2012, and completed his undergraduate studies at Indian School of Mines University, Dhanbad, India. His research specializes in Multimedia and Vision, Image Processing, and Machine Learning, with particular emphasis on fine-grained object recognition, object re-identification, visual tracking, adversarial attacks, and cross-modal recognition. He is a recipient of the Early Career Research Award from the Department of Science and Technology. His research group, the Visual Conception Group, maintains active partnerships with institutions including NUS Singapore, QUT Australia, NII Japan, and UiT Norway.'),
  ('163', 'Aasim Khan', 'aasim@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty//aasim.jpg', 'Ph.D. (2018), King''s College, London', '011-26907463', 'B-202 (R&D Block)', 'http://faculty.iiitd.ac.in/~aasim/', 'https://iiitd.ac.in/aasim', '["Global Governance and Policy","Technology Policy and Ethics","Institutional Change in the Global South","Social Networks and the Politics of Influence"]', '["Digital Politics and Ethics","Power and Mediation in World Politics","State and Society in the Global South","Concepts and Conceptual History in Social Sciences"]', NULL, '[]', '2026-06-23 12:51:04.853', '2026-06-23 12:51:06.806843', '2026-06-23 12:51:04.853', 'Dr. Aasim Khan is Assistant Professor at the Department of Social Sciences and Humanities, IIIT-Delhi. Aasim has specialization in global and South Asia studies with a focus on politics and public policy. His current research combines his interest in political and social theory of the ''global South'' with a focus on information technologies, social networks and new media and their entanglements with global and regional governance institutions. Aasim completed his BSc in Physics, Chemistry and Maths (St Stephen’s College, Delhi University) and then pursued an MA in mass communication (Jamia Millia Islamia, Delhi). He completed a second MA in global media and communication studies from the School of Oriental and African Studies (University of London) and worked as a journalist for several years in between. He then pursued his doctoral research at the India Institute, King''s College London, UK. He was awarded a PhD in Politics and Public Policy in 2018. Most recently, from 2022-2023, Aasim was a Visiting Scholar in Political Science at the Watson Institute for Public and International Affairs, Brown University, USA. Aasim has also raised several grants to fund his research, including the IMPRESS grant by the Indian Council for Social Science Research (ICSSR), and a Global Challenges Research Fund GCRF grant (in collaboration with the Goldsmiths, UK). He received the Global Institutes Studentships and the Mazumdar Fellowship (2012-2015) at the King''s India Institute. In 2014, he was awarded the Global Governance Futures fellowship by the GPPi Institute, Berlin, Germany. Since 2021, he has been an Associate Researcher at the Centre de Sciences Humaines (CSH), Delhi. Aasim has published extensively on themes related to his research interests, including articles in peer-reviewed journals Global Policy, India Review, SAMAJ, Third World Quarterly, Culture Unbound and Television and New Media among others. He has also contributed chapters to several edited volumes, most recently to an edited collection on the global post-truth crisis (Routledge, December, 2023). Aasim has himself co-edited two special issues on themes of technological change and institutions in the South Asia; the first a special issue for TVNM (Sage, 2019) on "Millennial India" and a more recent special section in Global Policy (November, 2023) on the role of influencers, titled "The Sound, The fury and The Silences." Over the past few years, Aasim has been invited for talks and lectures at various public and academic venues. He has delivered seminar talks at the Centre for Law and Governance (JNU), TISS Mumbai, Department of Political Science (JMI), TCPD at Ashoka University, Goldsmiths University (UK), Department of Social Sciences and Humanities IIT Jodhpur and at IIM Indore where he was a visiting faculty in 2019. As a Fulbright scholar in the United States, Aasim was a speaker at the Watson Institute Seminar Series (Brown University) and at the Centre for South Asia (Stanford University). Aasim worked for many years in broadcast news journalism (CNN-IBN) and international development (Oxfam GB) and is a regular contributor to The Book Review as well as research and development programs such as the Social Sciences Winter School held at French Institute in Pondicherry where he was a keynote speaker in November, 2023. Most recently, he was invited for a presentation on his research by the Centre for South Asia, Sciences Po, Paris (June 2024)'),
  ('164', 'Abhijit Mitra', 'abhijit@iiitd.ac.in', 'Assistant Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/abhijit.jpg', 'Ph.D. (2017), under joint Indo-UK collaboration between IIT Delhi and British Telecom (BT), UK in the area of Elastic Optical Networks.', '+91 011-26907542', 'A-605 (R&D Block)', 'http://faculty.iiitd.ac.in/~abhijit/', 'https://iiitd.ac.in/abhijit', '["Multi-band Optical Networks","Space Division Multiplexing","Quantum Key Distribution"]', '["Digital Communication Systems","Next Generation Optical Networks"]', NULL, '[]', '2026-06-23 12:51:05.552', '2026-06-23 12:51:07.069315', '2026-06-23 12:51:05.552', 'Dr. Abhijit Mitra is an Assistant Professor in the Department of Electronics and Communications Engineering (ECE) at IIIT-Delhi. He holds a PhD (2017) from IIT Delhi, supported by the British Telecom Fellowship. His professional experience spans over a decade, focusing on modeling and network planning for metro and core optical networks. He has published in major venues including the Proceedings of the IEEE, optical communications journals, and international conferences (OFC, ECOC). He has led funded research projects through DST, MIETY, and DRDO as principal or co-investigator. He is a recipient of the DST Inspire Faculty Fellowship (2017-2022), British Council Professional Achievement Award (2019), and was selected for Fulbright Post Doctoral Research Fellowship from USIEF. His expertise concentrates on multi-band optical networks, space division multiplexing, and quantum key distribution technologies.'),
  ('165', 'Angshul Majumdar', 'angshul@iiitd.ac.in', 'Professor (ECE, CSE)', 'ECE, CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/angshul.jpg', 'Ph.D. (2012), University of British Columbia', '011-26907493', 'A-606 (R&D Block)', 'http://faculty.iiitd.ac.in/~angshul/', 'https://iiitd.ac.in/angshul', '["Sparse Recovery","Low-rank matrix completion","Medical Imaging","Biomedical Signal Processing","Hyper-spectral Imaging","Collaborative Filtering"]', '["Image Processing","Collaborative Filtering"]', NULL, '[]', '2026-06-23 12:51:05.859', '2026-06-23 12:51:07.37872', '2026-06-23 12:51:05.859', '["Angshul Majumdar is a Professor at Indraprastha Institute of Information Technology, Delhi. He completed his Ph.D. from the University of British Columbia in 2012; he finished his thesis in a record time of less than two years. His research interests are in algorithms and applications of sparse signal recovery and low rank matrix recovery. Specifically, Angshul is interested in problems in biomedical signal processing and imaging. Angshul has written over 70 journal and conference papers since the inception of his research career in 2007. He has recently written a book on Compressed Sensing based MRI Reconstruction which is in print at Cambridge University Press."]'),
  ('166', 'Anmol Srivastava', 'anmol@iiitd.ac.in', 'Head (HCD),
Assistant Professor (HCD)', 'HCD', 'https://iiitd.ac.in/sites/default/files/images/faculty/anmol.jpg', 'Ph.D. (2019), IIT Guwahati, India', '011-26907467', 'A-404 (R&D Block)', NULL, 'https://iiitd.ac.in/anmol', '["AR/VR","The Metaverse","Tangible User Interfaces"]', '["AR/VR","The Metaverse","Tangible User Interfaces"]', NULL, '[]', '2026-06-23 12:51:06.167', '2026-06-23 12:51:07.68906', '2026-06-23 12:51:06.167', 'Dr. Anmol Srivastava is an Assistant Professor in the Human-Centered Design (HCD) department at IIIT-Delhi. He received his PhD in 2019 from IIT Guwahati. He specializes in Human-Computer Interaction with emphasis on emerging technologies, exploring AR/VR, the Metaverse, and Tangible User Interfaces to enhance user experience across various applications. Prior to joining IIIT-Delhi, he directed the UX & Interaction Design Program and XR & IxD Lab at UPES Dehradun''s School of Design. His doctoral research came from India''s pioneering UE and HCI Lab, where he developed expertise in designing systems that balance utility, usability, and creative potential. His research has earned multiple national and international awards.'),
  ('167', 'Anubha Gupta', 'anubha@iiitd.ac.in', 'Head (ECE),
Professor (ECE, CSE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/anubhag.jpg', 'Ph.D. (2006), IIT Delhi, India', '011-26907428', 'B-609 (R&D Block)', 'http://faculty.iiitd.ac.in/~anubha/', 'https://iiitd.ac.in/anubha', '["Computer Vision","Deep Learning/Machine Learning in healthcare applications","Cancer Imaging","Cardiovascular Disorders","FMRI/EEG/MRI/DTI Signal and Image Processing","Genomics Signal Processing","Sparse Reconstruction"]', '["Courses related to machine learning and signal processing"]', '["Member, Infosys Centre for Artificial Intelligence (CAI)","Core Member, Center of Excellence in Healthcare, IIIT-Delhi","SBILab, Deptt. of ECE, IIIT-Delhi"]', '[]', '2026-06-23 12:51:06.483', '2026-06-23 12:51:08.000157', '2026-06-23 12:51:06.483', 'Prof. Anubha Gupta graduated with a Ph.D. degree in Electrical Engineering from IIT Delhi in 2006. She did her bachelor''s and master''s in ECE from Delhi University in 1991 and 1997, respectively. She worked as Assistant Director with the Ministry of Information and Broadcasting, Govt. of India (through Indian Engineering Services) from 1993 to 1999 and, as faculty at NSUT-Delhi (2000-2008) and IIIT-Hyderabad (2011-2013), India. Currently, she is working as a Professor at IIIT-Delhi. In Dec 2013, she joined IIIT Delhi, where she is currently working as a Professor in the Deptt. of ECE and Deptt. of CSE. Earlier, she had served as the Dean of the Academic Affairs, and a member, Board of Governors of IIIT Delhi. Apart from her engineering interests, Prof. Gupta is deeply interested in education policy issues. She did her second master''s as a full time student from University of Maryland College Park, USA from 2008 to 2010. During this time, she worked as a project manager on a state policy related education project at the University System of Maryland, USA. On graduation, she worked as Director of Assessment at the Bowie State University, Maryland USA from Oct. 2010 to April 2011. Prof. Gupta has authored/co-authored more than 150 technical papers in scientific journals and conferences. She has published research papers in both engineering and education. Her research interests include computer vision, deep learning, machine learning and signal processing applied to healthcare applications including Cancer Imaging, Cancer Genomics, cardiology, and neuroscience. She is also interested in engineering education related issues. Prof. Gupta is a recipient of SERB POWER Fellowship, 2021 and IETE PROF SVC AIYA MEMORIAL AWARD-2022. She is a senior member of IEEE Signal processing Society and a member of IEEE Women in Engineering Society. Currently, she is the technical committee member of BISP, IEEE Signal Processing Society for the term 1/1/2025 to 12/31/2027. She served as an Associate Editor of IEEE Access journal, Associate Editor of IEEE Signal Processing Magazine eNewsletter, and Associate Editor, Frontiers in Neuroscience Methods in the past.'),
  ('168', 'Anuj Grover', 'anuj@iiitd.ac.in', 'Associate Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/anujg.jpg', 'Ph.D. (2015), IIT Delhi, India', '011-26907494', 'A-610 (R&D Block)', 'https://sites.google.com/iiitd.ac.in/anuj-grover', 'https://iiitd.ac.in/anujg', '["Ultra Low Power In-Memory Compute for edge computing and machine learning applications","Safety and security in hardware; and Error resilient energy efficient systems"]', '["Memory Design","VLSI Design","Solid State Devices","Theory of Inventive Problem Solving"]', NULL, '[]', '2026-06-23 12:51:06.786', '2026-06-23 12:51:08.298901', '2026-06-23 12:51:06.786', '["Dr. Anuj Grover has obtained Ph.D. from IIT Delhi in 2015, MS (Electronic Circuits and Systems) from UCSD in 2003, and B Tech (EE) from IIT Delhi in 2000. Prior to joining IIIT-Delhi, he had been working as Principal Engineer - Member of Technical Staff at STMicroelectronics, Greater NOIDA. In more than 18 years of experience in the semiconductor industry as a Memory Designer, he has worked on a wide range of technologies like Bulk CMOS, BCD, Imaging, UTBB-FDSOI CMOS, e-NVM across a range of feature sizes from 22nm to 0.35um. He has more than 50 publications across IEEE journals and conferences.","He has strong interest in Systematic Innovation and is trained on applying Theory of Inventive Problem Solving (TRIZ). He has been awarded TRIZ Level-3 Certification from MIT and MATRIZ. He has also been certified by World Intellectual Property Organization (WIPO) on application of TRIZ for patents. He has more than 20 granted patents and more than 10 patent applications in different stages of filing.","His current research interests include Sustainability in Circuits and Systems; In-Memory Compute for edge computing; Intelligent Product Development; Safety and Security in hardware; and Error Resilient Energy Efficient Systems."]'),
  ('169', 'Anuj Kumar', 'anuj.kumar@iiitd.ac.in', 'Assistant Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/anujkumar.jpg', 'Ph.D. (2021), Indian Institute of Technology, Roorkee', '011-26907366', 'A-602 (R&D Block)', 'https://sites.google.com/iiitd.ac.in/mind-lab/home?authuser=0', 'https://iiitd.ac.in/anujkumar', '["Nanofabrication and device physics","Resistive and magnetic memory technologies","Spintronic devices and topological spin textures","Synaptic and neuromorphic hardware","2D materials and van der Waals heterostructures"]', '["Nanoelectronics and nanoscale devices","Magnetism and spintronics","Emerging memory technologies","Advanced fabrication and characterization techniques"]', '["Centre for Quantum Technologies (CQT)"]', '[]', '2026-06-23 12:51:07.09', '2026-06-23 12:51:08.598313', '2026-06-23 12:51:07.09', '["Dr. Anuj Kumar received his Ph.D. from the Indian Institute of Technology Roorkee (IITR) in 2021 and was awarded the Excellence in Doctoral Research Award for his thesis. He then joined the Indian Institute of Science (IISc), Bangalore, as an Institute of Eminence Postdoctoral Fellow for one year. Subsequently, he worked as a Postdoctoral Research Fellow at the National University of Singapore (2022-25). He is a lifetime member of the Indian Physics Association and served as Joint Secretary of the Indian Physics Association, Roorkee Chapter, during his Ph.D. tenure. In recognition of his mentorship, he received the NUS High Inspiring Mentor Award (2024). He has published several high-impact papers in leading international journals and conferences.His research lies at the intersection of spintronics, electronics, and neuromorphic engineering, combining device physics and nanofabrication to develop next-generation memory and computing architectures. He collaborates closely with interdisciplinary teams spanning magnetism, materials science, and AI hardware."]'),
  ('170', 'Anuradha Sharma', 'anuradha@iiitd.ac.in', 'Head (Math),
Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/anuradhas.jpg', 'Ph.D. (2006), Panjab University, Chandigarh, India', '011-26907534', 'B-311 (R&D Block)', 'https://www.anuradhasharma.info/', 'https://iiitd.ac.in/anuradha', '["Algebraic Coding Theory","Number Theory and Algebra"]', '["Algebraic Coding Theory","Number Theory","Algebra","Quantum error-correction","DNA error-correction"]', NULL, '[]', '2026-06-23 12:51:07.396', '2026-06-23 12:51:08.911419', '2026-06-23 12:51:07.396', '["Anuradha Sharma is the Head and a Professor in the Department of Mathematics at IIIT-Delhi. She completed her B.Sc. (Honours), M.Sc., and Ph.D. degrees in Mathematics from the Centre for Advanced Study in Mathematics, Panjab University, Chandigarh, in 2000, 2002, and 2006, respectively. She was awarded the University Gold Medal for securing first position in her M.Sc. program. Prior to joining IIIT-Delhi, she served as an Assistant Professor in the Department of Mathematics at IIT Delhi for over five years and earlier at the Centre for Advanced Study in Mathematics, Panjab University, for three years. During her tenure at IIT Delhi, she received the prestigious Kusuma Outstanding Young Faculty Fellowship.","Her primary research area is Algebraic Coding Theory, with additional interests in Number Theory and Algebra. She has authored around 65 research papers published in leading international journals such as Finite Fields and Their Applications, Designs, Codes and Cryptography, and IEEE Transactions on Information Theory. She is also a co-author of the book entitled \"Codes and Modular Forms: A Dictionary\" (with Minjia Shi, YoungJu Choie, and Patrick Solé). Her Erdős number is 3.","Her research has been supported by major national funding agencies, including the Department of Science and Technology (DST), the Science and Engineering Research Board (SERB), and the IHUB-Anubhuti–IIITD Foundation."]'),
  ('171', 'Arani Bhattacharya', 'arani@iiitd.ac.in', 'Assistant Professor (CSE, ECE)', 'CSE, ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/arani.jpg', 'Ph.D. (2019), Stony Brook University', '011-26907434', 'B-510 (R&D Block)', 'http://faculty.iiitd.ac.in/~arani/', 'https://iiitd.ac.in/arani', '["Low latency compute and machine learning services","Video streaming and physical layer of wireless networks"]', '["Wireless Networks","Operating Systems","Computer Organization","Systems Programming"]', NULL, '[]', '2026-06-23 12:51:07.715', '2026-06-23 12:51:09.221263', '2026-06-23 12:51:07.715', '["Arani Bhattacharya earned his Ph.D. degree from Stony Brook University in Computer Science in 2019. His research experience is in applications of wireless networks and edge computing, with a focus on applying algorithms and machine learning to prototype emerging applications. Recently, these applications have been related to cloud-assisted autonomous vehicles, traffic surveillance and Industry 4.0. He has published papers in several reputed venues such as USENIX Annual Technical Conference (ATC), ACM UbiComp and IEEE Transactions on Vehicular Technology. He regularly serves as a technical program committee member of multiple conferences such as ACM Internet Measurement Conference (IMC), IEEE ICDCS and ACM MMSys. He has also been part of the organizing committee of international conferences like ACM MMSys 2026 and ACM COMPASS 2024. His research has been funded by both private and government funding agencies like ANRF and Cisco."]'),
  ('172', 'Arjun Ray', 'arjun@iiitd.ac.in', 'Assistant Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/arjunr.jpg', 'Ph.D. (2018), CSIR-IGIB', '011-26907438', 'A-310 (R&D Block)', 'https://raylab.iiitd.edu.in/', 'https://iiitd.ac.in/arjun', '["Deciphering the mechanism of CRISPR-Cas9","Elucidating molecular interactions in the reverse cholesterol pathway","Structural genomic problems"]', '["Biophysics","Computer-aided Drug Design","Protein biology"]', NULL, '[]', '2026-06-23 12:51:07.99', '2026-06-23 12:51:09.508391', '2026-06-23 12:51:07.99', '["Dr. Arjun Ray is a computational structural biologist and earned his Ph.D. degree from CSIR-IGIB. His formal education in the field of chemistry and biophysics led him to be interested in understanding how biological processes are carried out by three-dimensional interactions. His previous researches include developing methods and tools in the field of structure prediction and force distributed analysis of lipids, deciphering mechanistic understanding of interactions between various biological molecules and working with multi-scale systems. As a structural biologist, he has been regularly working with techniques for structure prediction, molecular dynamics simulations and biomolecular docking. Along with his research endeavours, he has held several positions such former President of Regional Student Group (India) for the International Society for Computational Biology."]'),
  ('173', 'Arun Balaji Buduru', 'arunb@iiitd.ac.in', 'Associate Professor (CSE, HCD)', 'CSE, HCD', 'https://iiitd.ac.in/sites/default/files/images/faculty/arunb.jpg', 'Ph.D. (2016), Arizona State University, USA', '011-26907469', 'B-504 (R&D Block)', 'http://faculty.iiitd.ac.in/~arunb/', 'https://iiitd.ac.in/arunb', '["Affective AI","Usable Security","Computational Linguistics"]', '["Foundations to Computer Security","Advanced Programming","Usable Security and Privacy"]', '["Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)","Centre of Technology in Policing (CTP)","Infosys Centre for Artificial Intelligence (CAI)"]', '[]', '2026-06-23 12:51:08.324', '2026-06-23 12:51:09.846338', '2026-06-23 12:51:08.324', '["Arun Balaji Buduru is an Associate Pprofessor at Indraprastha Institute of Information Technology, Delhi. He received his Ph.D. in Computer Science, specializing in Information Assurance, at Arizona State University in 2016. His research interests include cyber security, reinforcement learning and stochastic planning. He received his B.E. degree in Computer Science in 2011 from Anna University at Chennai, India. He has worked as a research intern as part of Cisco IoT Architecture Group. His current research focuses on adaptive user re-authentication on touch-based devices, predicting security breaches in critical cyber infrastructures, and user behavior based adaptive IoT device reconfiguration"]'),
  ('174', 'Ashish Kumar Pandey', 'ashish.pandey@iiitd.ac.in', 'Associate Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/ashishpandey.jpg', 'Ph.D. (2018), The University of Illinois at Urbana-Champaign, USA.', '011-26907461', 'B-307 (R&D Block)', 'https://sites.google.com/iiitd.ac.in/akpandey/home', 'https://iiitd.ac.in/ashishk', '["Partial Differential Equations (PDEs)"]', '["Stability or instability of solutions of nonlinear PDEs arising as physical models"]', NULL, '[]', '2026-06-23 12:51:08.629', '2026-06-23 12:51:10.144174', '2026-06-23 12:51:08.629', 'Ashish Pandey obtained his Ph.D. in Mathematics from the University of Illinois at Urbana-Champaign, USA in April 2018. He completed his Integrated M.Sc. in Mathematics from National Institute of Science Education and Research (NISER), Bhubaneswar, India in May 2012. His primary area of research is Partial Differential Equations (PDEs). He tries to understand existence, well-posedness, stability or instability of solutions of nonlinear PDEs arising as physical models. He uses tools from Harmonic analysis and Operator theory.'),
  ('175', 'Bapi Chatterjee', 'bapi@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/bapi.jpg', 'Ph.D. (2018), Chalmers University of Technology, Gothenburg, Sweden', '011-26907371', 'B-402 (R&D Block)', 'https://bapi.github.io', 'https://iiitd.ac.in/bapi', '["Distributed Machine Learning","Concurrent Data Structures","Neural Architecture Search","Learned Index Structures"]', '["Data Structures","Parallel/Distributed/High-performance Computing","Machine Learning","Optimization and related subjects"]', '["Distributed Computing and Learning Lab","Infosys Centre for Artificial Intelligence (CAI)"]', '[]', '2026-06-23 12:51:08.943', '2026-06-23 12:51:10.453171', '2026-06-23 12:51:08.943', 'Dr. Bapi Chatterjee is an Assistant Professor in the Department of Computer Science and Engineering at IIIT-Delhi. He received his PhD in Computer Science and Engineering (2018) from Chalmers University of Technology, Gothenburg, Sweden. He brings diverse research experience from multiple institutions, having spent over two years as a postdoctoral fellow at the Institute of Science and Technology Austria, and previously worked as a researcher at IBM India Research Lab for two years following his doctorate. His current academic interests center on four main areas: Distributed Machine Learning, Concurrent Data Structures, Neural Architecture Search, and Learned Index Structures. He is associated with both the Distributed Computing and Learning Lab and the Infosys Centre for Artificial Intelligence at IIIT-Delhi.'),
  ('176', 'Chanekar Prasad Vilas', 'prasad@iiitd.ac.in', 'Assistant Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/chanekar.jpg', 'Ph.D. (2018), University of Maryland, USA', '011-26907374', 'B-610 (R&D Block)', NULL, 'https://iiitd.ac.in/chanekar', '["Kinematics","Dynamics","Control and optimization of large-scale engineering systems with applications to system co-design","Robotics","","Renewable Energy Systems","Power Networks","Neuroscience"]', '["Optimal control","Nonlinear control","Robotics"]', NULL, '[]', '2026-06-23 12:51:09.239', '2026-06-23 12:51:10.753944', '2026-06-23 12:51:09.239', 'Dr. Chanekar Prasad Vilas received his undergraduate degree in Mathematics and Computing from the Indian Institute of Technology, Kharagpur, India and an AMIE degree in Mechanical Engineering from the Institution of Engineers, India. He then obtained M.Sc. and Ph.D. degrees in Mechanical Engineering from the Indian Institute of Science, Bangalore, India and the University of Maryland, College Park, USA respectively. He was a Post-Doctoral researcher in the Department of Mechanical and Aerospace Engineering at the University of California, San Diego, USA.'),
  ('177', 'Debajyoti Bera', 'dbera@iiitd.ac.in', 'Associate Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/debajyoti.jpg', 'Ph.D. (2010), Boston University, USA', '011-26907442', 'B-508 (R&D Block)', 'http://faculty.iiitd.ac.in/~dbera/', 'https://iiitd.ac.in/dbera', '["Algorithms","Complexity Theory","Quantum Computing"]', '["Algorithms","Complexity Theory","Quantum Computing"]', NULL, '[]', '2026-06-23 12:51:09.565', '2026-06-23 12:51:11.07584', '2026-06-23 12:51:09.565', 'Debajyoti Bera is currently an Associate Professor in IIIT-Delhi. He received Ph.D. in Computer Science from Boston University in 2010, and B.Tech. in Computer Sc. and Engg. from IIT-Kanpur in 2002. He is currently involved in active research on topics in quantum computing and theoretical computer science. and B.Tech. projects.'),
  ('178', 'Debarka Sengupta', 'debarka@iiitd.ac.in', 'Professor (CB, CSE)', 'CB, CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty//debarka.jpg', 'Ph.D. (2014), Jadavpur University', '011-26907446', 'A-306 (R&D Block)', 'https://www.thesenguptalab.com', 'https://iiitd.ac.in/debarka', '["Computational Genomics, Machine Learning, Bioinformatics"]', '["Algorithms, statistics, machine learning, computational biology"]', '["Infosys Centre for Artificial Intelligence","Centre for Computational Biology"]', '[]', '2026-06-23 12:51:09.797', '2026-06-23 12:51:11.304941', '2026-06-23 12:51:09.797', 'Debarka is an Professor of Computational Biology and Computer Science at IIIT-Delhi. He is also an honorary Associate Professor at the Queensland University of Technology-Brisbane. Debarka carried out his doctoral and post-doctoral research in the Machine Intelligence Unit of the Indian Statistical Institute and Genome Institute of Singapore, respectively. His group has been among the first to introduce big data algorithms in the field of single-cell genomics. He received INSPIRE faculty Award in 2015 by the Government of India. His lab invented and commercialized a panel of eleven platelet genes to track the early onset of cancer.'),
  ('179', 'Debidas Kundu', 'debidas@iiitd.ac.in', 'Assistant Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/debidas.jpg', 'Ph.D. (2018), IIT, Kharagpur, India', '011-26907465', 'A-606 (R&D Block)', 'https://sites.google.com/iiitd.ac.in/msrl', 'https://iiitd.ac.in/debidas', '["Analytical techniques for surface electromagnetics, metamaterial and metasurface, reconfigurable intelligent surface, reflectarray, scattering and polarization control of the electromagnetic wave."]', '["Advanced Electromagnetic Theory","Analytical and Computational Techniques in Electromagnetics","EMI/ EMC Techniques","Analog CMOS Circuit Design","Applied Electromagnetics with Metasurface"]', NULL, '[]', '2026-06-23 12:51:10.057', '2026-06-23 12:51:11.581043', '2026-06-23 12:51:10.057', 'Debidas Kundu received his Ph. D. degree from Dept. of Electronics and Electrical Communication Engineering, Indian Institute of Technology Kharagpur, India in June 2018. After submitting his thesis, he was with BITS Pilani KK Birla Goa Campus as a Visiting Faculty from January 2018 to December 2018. In 2018, he received the DST-INSPIRE Faculty award and subsequently joined the ECE Department of IIT Roorkee as an INSPIRE Faculty in January 2019. From April 2022 to April 2023 he worked as visiting researcher (Post-Doc) at Carleton University, Canada. Dr. Kundu is an author and co-author of more than 30 reputed journals and conference publications. He serves as an active reviewer for renowned journals, such as IEEE Trans. on Antennas and Propagation, IEEE Trans. on Electromagnetic Compatibility, IEEE AWPL, AIP Applied Physics Letters, AIP journal of Applied Physics, OSA Optics Express, Scientific Reports, etc.  He is a recipient of the Young Scientist Award from URSI-RCRS and URSI-GASS in 2020 and 2023, respectively. His current research mainly includes analytical techniques for surface electromagnetics, metamaterial and metasurface, reconfigurable intelligent surface, reflectarray, scattering and polarization control of the electromagnetic wave.'),
  ('180', 'Debika Banerjee', 'debika@iiitd.ac.in', 'Associate Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/debika.jpg', 'Ph.D. (2017), Harish-Chandra Research Institute, Allahabad', '011-26907358', 'B-310 (R&D Block)', 'https://sites.google.com/view/debikabanerjee/home', 'https://iiitd.ac.in/debika', '["Analytic and Probabilistic Number Theory"]', '["Real Analysis","Complex Analysis","Algebra","Number Theory"]', NULL, '[]', '2026-06-23 12:51:10.367', '2026-06-23 12:51:11.892005', '2026-06-23 12:51:10.367', 'Dr. Debika Banerjee obtained Ph.D. in Mathematics from Harish-Chandra Research Institute, Allahabad in 2017 and M.Sc. in Mathematics from IIT Kanpur in 2011. Prior to joining IIIT-Delhi, she was a National Post Doctoral Fellow (NPDF) at IISER Pune from 2017 to 2019. She worked as a Post Doctoral Fellow at Technion, Israel from 2016 to 2017.'),
  ('181', 'Deepak Prince', 'deepak@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/deepak.jpg', 'Ph.D. (2022), Sociology, Shiv Nadar University', '011-26907595', 'A-210 (R&D Block)', '#', 'https://iiitd.ac.in/deepak', '["Anthropology of technology, screens and interfaces, political anthropology, violence and public art"]', '["Science Technology and Society, Kinship, Visuality and Media, Political anthropology, Violence, Anthropological disciplinarity"]', NULL, '[]', '2026-06-23 12:51:10.676', '2026-06-23 12:51:12.185236', '2026-06-23 12:51:10.676', 'Deepak Prince is an anthropologist with an interest in the sociality of technology (specifically, screen-based computational technologies) and in practices of imagination. Other interests include political anthropology, violence and public art. Deepak was founding sociology faculty at GITAM, Hyderabad. He has also taught at Shiv Nadar University and at IIT Jodhpur. He has an MA in economics from the Delhi School of Economics and a PhD in Sociology (Anthropology) from Shiv Nadar. He is on the editorial board of the STS journal, Tecnoscienza, and reviews for Wenner-Gren. Deepak co-founded 0penstudi0, an art collective taking an ethnographic approach to public art projects produced collaboratively with local communities. Presently, he is working on a set of problems related to gig-work.'),
  ('182', 'Diptapriyo Majumdar', 'diptapriyo@iiitd.ac.in', 'Assistant Professor (CSE, Math)', 'CSE, Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/diptapriyo.jpg', 'Ph.D. (2018), The Institute of Mathematical Sciences (IMSc), Chennai', '011-26907373', 'B-501 (R&D Block)', 'https://diptapriyomajumdar.wixsite.com/toto', 'https://iiitd.ac.in/diptapriyo', '["Parameterized Complexity","Graph Algorithms","Theory of Preprocessing Algorithms","Graph Theory"]', '["Courses related to algorithms","Discrete Mathematics","Theoretical Computer Science","Optimization","Combinatorics","Graph Theory"]', NULL, '[]', '2026-06-23 12:51:10.981', '2026-06-23 12:51:12.496539', '2026-06-23 12:51:10.981', 'Dr. Diptapriyo Majumdar obtained his Ph.D. degree in Theoretical Computer Science from The Institute of Mathematical Sciences (IMSc), Chennai, India in October-2018. He has spent 2 years 11 months at Royal Holloway, University of London, UK as a postdoctoral researcher before joining IIIT-Delhi in December-2021. He received his M.Tech degree in Computer Science from Indian Statistical Institute, Kolkata, India. His research interests are primarily at the intersection of Graph Theory and Design and Analysis of Algorithms. He is particularly interested in designing fixed-parameter algorithms for computationally hard problems arising in graph theory.'),
  ('183', 'G.P.S. Raghava', 'raghava@iiitd.ac.in', 'Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/raghava.jpg', 'Ph.D. (1996), Institute of Microbial Technology, Chandigarh.', '011-26907444', 'A-302 (R&D Block)', 'http://webs.iiitd.edu.in/raghava/', 'https://iiitd.ac.in/raghava', '["Application of computer science in the field of biomedical","Artificail intelligence based models for desiging drugs, vaccines and disease biomarkers","Development of open source applications (web servers, standalone software, mobile apps) for serving scientific community working in healthcare"]', '["Application of Artificial Intelligence in Biomedical Sciences","Big Data Mining in Healthcare"]', NULL, '[]', '2026-06-23 12:51:11.289', '2026-06-23 12:51:12.806743', '2026-06-23 12:51:11.289', 'Prof. G. P. S. Raghava received his M.Tech. from IIT Delhi and his Ph.D. from CSIR-IMTECH, Chandigarh. He served as a Postdoctoral Fellow at the University of Oxford, UK, as a Bioinformatics Specialist at UAMS, USA, and as a Visiting Professor at POSTECH, South Korea. He worked as a Scientist at CSIR-IMTECH, Chandigarh, for nearly three decades (1986–2016). Prof. Raghava is a champion of open source software and open access, all the resources develoed at his group are free for the scientific community. His group has developed and maintained more than 300 bioinformatics software, databases and web servers, the highest number developed by a single research group worldwide. These resources are extensively used by the global scientific community, receiving approximately 200,000 hits per day. He has published over 300 research papers in reputed journals, with an average impact factor of around 4.0. His publications have received more than 36,000 citations, with an h-index of 97 and an i10-index of 287. He is a recipient of several prestigious national honors, including the Shanti Swarup Bhatnagar Prize, the National Bioscience Award, and the J. C. Bose National Fellowship. He is a Fellow of major Indian science academies (FNA, FASc, FNASc). In 2014, he was recognized as a “Highly Cited Researcher” by Thomson Reuters, ranking among the top 1% of researchers worldwide in computer science.'),
  ('184', 'Ganesh Bagler', 'bagler@iiitd.ac.in', 'Head (CB),
Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/gbagler.jpg', 'Ph.D. (2007), CSIR-Centre for Cellular and Molecular Biology', '011-26907443', 'A-305 (R&D Block)', 'https://cosylab.iiitd.edu.in', 'https://iiitd.ac.in/bagler', '["Complex Systems","Computational Gastronomy","Computational Biology","Network Science","Bioinformatics","Computational Creativity"]', '["Computational and Systems Biology","Network Science","Network Biology","Computational Gastronomy","Computational Creativity","Philosophy of Science"]', '["Complex Systems Laboratory","Infosys Centre for Artificial Intelligence (CAI)"]', '[]', '2026-06-23 12:51:11.595', '2026-06-23 12:51:13.104256', '2026-06-23 12:51:11.595', 'Ganesh Bagler is a computational researcher trained in physics, computer science, and computational biology. Prof. Bagler is well-known for his pioneering research in ‘Computational Gastronomy.’ By building keystone data repositories, algorithms, and applications, he has established the foundations of this emerging data science that blends food with artificial intelligence. Trailblazing research from his lab has significantly contributed to this niche area that deals with food, flavors, nutrition, and public health. A prolific interdisciplinary scientist, voracious reader, science communicator, and TEDx speaker, Ganesh Bagler is an explorer driven by curiosity. He enjoys probing the structure, function, evolution, and design of complex systems (proteins, brain, health, cuisines, languages, and creativity). Prof. Bagler has an audacious dream of transforming the global food landscape by ‘Making Food Computable.’'),
  ('185', 'Gaurav Ahuja', 'gaurav.ahuja@iiitd.ac.in', 'Associate Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/gauravahuja.jpg', 'Ph.D. (2015), University of Cologne, Germany', '011-26907475', 'A-303 (R&D Block)', 'https://ahuja-lab.in/', 'https://iiitd.ac.in/gauravahuja', '["Identification","Deorphanization and characterization of ectopically expressed GPCRS"]', '["Chemoinformatics","Genetics","Molecular Biology","Biostatistics"]', NULL, '[]', '2026-06-23 12:51:11.923', '2026-06-23 12:51:13.428168', '2026-06-23 12:51:11.923', 'Gaurav Ahuja graduated summa cum laude from the University of Cologne, Germany with Ph.D. in Natural Sciences. He is a molecular biologist by training and possesses a vast experience in functional genomics, especially in dissecting complex biological mechanisms using genome-editing and next generation sequencing-based techniques. After the completion of his Ph.D. degree, he worked as a Post Doctoral Fellow at several renowned institutes, including Center for Molecular Medicine Cologne, Max Planck Institute for Ageing and Lee Kong Chian School of Medicine, Singapore. During this period he worked on multiple model systems, including human pluripotent stem cells, zebrafish, mice and killifish. He has published 14 research articles in peer-reviewed International journals (~250 citations). In addition to this, he also reviewed articles submitted to Nature Publishing Group (Cell Death & Diseases and Scientific Reports). Recently, Dr. Ahuja was shortlisted for the prestigious INSPIRE Faculty Fellowship.'),
  ('186', 'Gaurav Arora', NULL, 'Associate Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/gaurava.jpg', 'Ph.D. (2017), Iowa State University', '011-26907547', 'B-206 (R&D Block)', 'https://gauravaroraecon.wordpress.com/', 'https://iiitd.ac.in/gaurava', '["Natural Resource & Agricultural Economics","Ecological Economics","Applied Econometrics","Industrial Organization","Applied Game Theory","Spatial Analyses","Remote"]', '["Applied econometrics","Applied microeconomics","Spatial statistics and spatial econometrics"]', NULL, '[]', '2026-06-23 12:51:12.209', '2026-06-23 12:51:13.717641', '2026-06-23 12:51:12.209', 'Gaurav Arora received his Ph.D. in Economics at Iowa State University in January, 2017. As part of his Ph.D. dissertation work, he combined applied economics models with remote sensing tools to study the impacts of local infrastructure, climate change and conservation policy on regional land use changes for Agroecosystems. He also designed and implemented a satellite image-processing algorithm to characterize land use change using historical Landsat sensor data. He was awarded James R. Prescott scholarship in 2016 for outstanding creativity in research, and Earl O. Heady Fellowship in 2012 for academic excellence at the Department of Economics, Iowa State University. Prior to his Ph.D., Gaurav received Master of Science in Agricultural and Resource Economics at the University of Arizona, and Bachelor of Technology in Environmental Engineering at Indian School of Mines, Dhanbad.'),
  ('187', 'Gautam Shroff', 'gautam.shroff@iiitd.ac.in', 'Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/gautam.shroff.jpg', 'Ph.D. (1990), Rensselaer Polytechnic Institute Troy, NY', '011-26907488', 'A-510 (R&D Block)', '#', 'https://iiitd.ac.in/gautam', '["Analogical reasoning","Machine-learning for finance","Tools for accelerating research"]', '["Analogical reasoning","Machine-learning for finance","Tools for accelerating research"]', NULL, '[]', '2026-06-23 12:51:12.518', '2026-06-23 12:51:14.026835', '2026-06-23 12:51:12.518', 'Dr. Gautam Shroff is a Professor in the Department of Computer Science and Engineering at IIIT-Delhi. He received his Ph.D. (1990) from Rensselaer Polytechnic Institute Troy, NY, and his B.Tech in Electrical Engineering from IIT Kanpur (1985). He has held leadership roles at TCS Research since 1998, serving as head of the organization from 2017 onward. He previously taught at Caltech (1990-91) and IIT Delhi''s Computer Science department (1991-1997). He holds fellowships from both TCS and the Indian National Academy of Engineering. His scholarly output includes over 140 research papers spanning computational mathematics, distributed systems, software engineering, AI, machine learning, and natural language processing. His current research focuses on analogical reasoning, machine-learning applications in finance, and methodologies for enhancing research acceleration.'),
  ('188', 'Gayatri Nair', 'gayatri@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/gayatri.jpg', 'Ph.D. (2016), Jawaharlal Nehru University, New Delhi', '011-26907362', 'B-212 (R&D Block)', '#', 'https://iiitd.ac.in/gayatri', '["Informal Labour","Urban Informalities","Technology, Gender, and Caste","Digital work and platform economy","Future of Work(ers)","Resource-based livelihoods"]', '["Sociological Theory","Technology and Work","Economic Sociology","Urban Sociology"]', NULL, '[]', '2026-06-23 12:51:12.823', '2026-06-23 12:51:14.337542', '2026-06-23 12:51:12.823', 'Gayatri Nair is Assistant Professor of Sociology, at the Department of Social Sciences and Humanities, Indraprastha Institute of Information Technology Delhi, India. Her research interests lie in urban informal labour with an emphasis on the question of caste, gender and technology. With a focus on political economy, she has published work that interrogates the role of caste and gender in shaping ‘traditional’ livelihoods and new forms of work specifically platform-based gig work; also detailing how workers organise. This work has appeared in journals such as Contemporary South Asia, Journal of South Asian Development and the Sociological Bulletin. Her recent book is ''Set Adrift; Capitalist Transformations and Community Politics Along Mumbai''s Shore’ published by the Oxford University Press (2021).'),
  ('189', 'J. V. Meenakshi', 'meena@iiitd.ac.in', 'Head (SSH),
Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/jvmeenakshi.jpg', 'Ph.D. (1991), Cornell University', '011-26907535', 'B-205 (R&D Block)', 'https://ssh.iiitd.ac.in/CV_JVM.pdf', 'https://iiitd.ac.in/jvmeenakshi', '["Economics of food, nutrition and health","Agricultural and water markets, irrigation and price policy","Causal evaluation of policies and interventions"]', '["Economic policy","Causal inference","Econometrics"]', NULL, '[]', '2026-06-23 12:51:13.133', '2026-06-23 12:51:14.647622', '2026-06-23 12:51:13.133', 'J.V. Meenakshi is an agricultural economist. Her research areas include the economics of rural health, nutrition and food; agricultural and water markets; and causal evaluations of agricultural, labour and nutrition interventions.  Her research is policy-oriented; and the geographical focus of her work extends beyond India to include several countries in sub-Saharan Africa.  It is informed by active collaborations with nutritionists, medical professionals, and policy makers, and uses a mix of field-based research and multiple nationally-representative data sets.  She has served on various national and international committees, including as a member of India''s National Statistical Commission. She is a co-editor of Food Policy.'),
  ('190', 'Jainendra Shukla', 'jainendra@iiitd.ac.in', 'Associate Professor (CSE, HCD)', 'CSE, HCD', 'https://iiitd.ac.in/sites/default/files/images/faculty/Jainendra.jpg', 'Ph.D. (2018), Universitat Rovira i Virgili (URV), Spain', '011-26907523', 'A-410 (R&D Block)', 'https://jainendra.in', 'https://iiitd.ac.in/jainendra', '["Affective Computing","Human-Computer Interaction","Social Robotics","Ubiquitous Computing"]', '["Affective Computing","Machine Learning","Social Robotics"]', '["Infosys Centre for Artificial Intelligence (CAI)","Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)","Human-Machine Interaction Lab (HMI)"]', '[]', '2026-06-23 12:51:13.445', '2026-06-23 12:51:14.962463', '2026-06-23 12:51:13.445', '["» A. B., Deeptanshu, S. Gulati and J. Shukla, \"Artificial Intelligence Driven Predictive Analysis of Acoustic and Linguistic Behaviors for ASD Identification\", IEEE Transactions on Artificial Intelligence, vol. 5, no. 11, pp. 5709-5719, Nov. 2024.","» R. Vatsal, S. Mishra, R. Thareja, M. Chakrabarty, O. Sharma and J. Shukla, \"An Analysis of Physiological and Psychological Responses in Virtual Reality and Flat Screen Gaming\" IEEE Transactions on Affective Computing, pp 1-15, 2024.","» A. Sarkar, P. R. Behera, and J. Shukla, \"Multi-Source Transfer Learning for Facial Emotion Recognition Using Multivariate Correlation Analysis\" Scientific Reports, vol. 13, no. 1, p. 21004, 2023.","» V. Jain, M. Leekha, R. R. Shah, and J. Shukla, \"Exploring Semi-Supervised Learning for Predicting Listener Backchannels\" in Proceedings of the 2021 CHI Conference on Human Factors in Computing Systems, CHI’21, pp 1-12, May 8-13, Yokohama, Japan, 2021.","» D. Verma, S. Bhalla, D. Sahnan, J. Shukla, and A. Parnami, \"Expressear: Sensing Fine-Grained Facial Expressions With Earables\" Proc. ACM Interact. Mob. Wearable Ubiquitous Technol., UbiComp/ISWC’21, vol. 5, September 21-26, 2021.","» J. Shukla, M. Barreda-Angeles, J. Oliver, G. Nandi, and D. Puig, \"Feature Extraction and Selection for Emotion Recognition From Electrodermal Activit IEEE Transactions on Affective Computing, 12(4), 857-869, 2019."]'),
  ('191', 'Jaspreet Kaur Dhanjal', 'jaspreet@iiitd.ac.in', 'Assistant Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/jaspreet.jpg', 'Ph.D. (2019), IIT Delhi, India', '011-26907522', 'A-307 (R&D Block)', 'https://dhanjal-lab.iiitd.edu.in/', 'https://iiitd.ac.in/jaspreet', '["Cancer genomics, personalized medicine, drug design and discovery"]', '["Introduction to Quantitative Biology","Cell Biology and Biochemistry"]', NULL, '[]', '2026-06-23 12:51:13.747', '2026-06-23 12:51:15.25586', '2026-06-23 12:51:13.747', 'Dr. Jaspreet Kaur Dhanjal received her PhD degree from Indian Institute of Technology Delhi (IITD) in 2019. She has then worked as a Postdoctoral Fellow at the National Institute of Advanced Industrial Science and Technology (AIST), Tsukuba Japan. Her research interests have been at the interface of computation, cellular and molecular biology. In particular, she is interested in studying cancer genomics for designing personalized therapeutics. She is also interested in exploring the mechanism of action of bioactive compounds from natural sources. She has co-authored over 30 papers in peer-reviewed international journals, 04 book chapters and over 10 international conference participation/presentations.'),
  ('192', 'Kalpana Shankhwar', 'kalpana@iiitd.ac.in', 'Assistant Professor (HCD)', 'HCD', 'https://iiitd.ac.in/sites/default/files/images/faculty/kalpana.jpg', 'Ph.D. (2022), National Taiwan University', '011-26907496', 'A-403 (R&D Block)', 'https://etidm.iiitd.edu.in/', 'https://iiitd.ac.in/kalpana', '["Fundamental and industrial applications of extended reality (XR)","Haptic technologies in manual milling operations and welding systems"]', '["Fundamental and industrial applications of extended reality (XR)","Haptic technologies in manual milling operations and welding systems"]', NULL, '[]', '2026-06-23 12:51:14.054', '2026-06-23 12:51:15.562419', '2026-06-23 12:51:14.054', 'Kalpana Shankhwar holds a Ph.D. degree in Mechanical Engineering from National Taiwan University (2022). She has completed her Masters in Mechanical Engineering from IIT Guwahati (2015) and Bachelor of Engineering also in Mechanical Engineering from Shri G. S. Institute of Technology and Science, Indore (2012). Her research focuses on fundamental and industrial applications of extended reality (XR) and haptic technologies in manual milling operations and welding systems. She has published her work in eight reputed international peer-reviewed SCI journals. Prior to her Ph.D., she worked as an Assistant Professor at Kalinga Institute of Industrial Technology (2015-2017). Furthermore, she also has worked in an automobile industry, MAN Trucks India Pvt. Ltd., as a Graduate Engineer Trainee (2012-2013). During her Ph.D., she was awarded three prestigious scholarships: The Outstanding International Doctoral Student Scholarship, CTCI Foundation Science and Technology Research Scholarship, and Chung Hwa Rotary Educational Foundation Scholarship. Her current research interests include augmented reality (AR), virtual reality (VR), mixed reality (MR), haptic technology, digital twin, artificial intelligence, and finite element method (FEM).'),
  ('193', 'Kaushik Kalyanaraman', 'kaushik@iiitd.ac.in', 'Assistant Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/kaushik.jpg', 'Ph.D. (2015), University of Illinois at Urbana-Champaign', '011-26907537', 'B-302 (R&D Block)', NULL, 'https://iiitd.ac.in/kaushik', '["Discretizations and applications of analysis, geometry, and topology"]', '["Scientific Computing, Numerical Solution of Partial Differential Equations, Differential Geometry, Advanced Linear Algebra, Real Analysis"]', NULL, '[]', '2026-06-23 12:51:14.272', '2026-06-23 12:51:15.786975', '2026-06-23 12:51:14.272', '["Kaushik Kalyanaraman is an Applied and Computational Mathematician. His broad research interests lie in the applications and discretizations of analysis, geometry, and topology. More concretely, his work focuses on structure-preserving and compatible discretizations of partial differential equations, particularly, Maxwell’s equations; in discretizations of calculus on manifolds, particularly, discrete exterior calculus; on applications of differential geometry and algebraic topology to problems in computer graphics and algorithms for machine learning; and, in recent years, on explorations in optimal transport, optimization on manifolds, and Bayesian persuasion.","His teaching interests span the algorithmic, computational, and theoretical aspects of analysis, geometry, and topology, exemplified by, but not limited to, courses at IIIT-Delhi such as Scientific Computing, Numerical Solution of Partial Differential Equations, Calculus in R^n with Applications, Differential Geometry, Advanced Linear Algebra, and Real Analysis in Metric Spaces. He also maintains a learning side interest in the philosophies of computing, mathematics, and science.","Kaushik received a B.E. in Electrical and Electronics Engineering from Anna University, Chennai (2005), an M.Tech. in Electrical Engineering from the Indian Institute of Technology, Bombay (2008), and a Ph.D. in Computer Science from the University of Illinois at Urbana–Champaign (2015). He previously served as a member of technical staff at Computational Research Laboratories, Pune, India (2008–2009), and as a postdoctoral fellow at the Scientific Computation Research Center, Rensselaer Polytechnic Institute, Troy, New York (2015–2017). At IIIT-Delhi, he served as the Head of the Department of Mathematics from April 2022 to December 2025."]'),
  ('194', 'Kiriti Kanjilal', 'kanjilal@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/kanjilal.jpg', 'Ph.D. (2018), Washington State University', '011-26907558', 'B-208 (R&D Block)', 'https://sites.google.com/site/kanjilaleconomics', 'https://iiitd.ac.in/kanjilal', '["Industrial Organization","Applied Game Theory","Behavioural and Experimental Economics","Natural Resource Economics"]', '["Game Theory","Industrial Organization","Macroeconomics"]', NULL, '[]', '2026-06-23 12:51:14.573', '2026-06-23 12:51:16.088012', '2026-06-23 12:51:14.573', 'Kiriti Kanjilal completed his 5 year Integrated Masters in Economics at the University of Hyderabad in 2013 and defended his Ph.D. in Economics at Washington State University in May 2018. His dissertation was titled Essays in Behavioral Industrial Organization and Natural Resource Economics. His research interests are primarily in the fields of microeconomics, game theory, industrial organization, environmental economics and behavioral economics. He also has experience in conducting economic experiments. He uses Mathematica, Stata and z-Tree for research. Apart from research, he also has taught courses in macroeconomics and finance during his Ph.D.'),
  ('195', 'Manohar Kumar', 'manohar.kumar@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/Manohar-Kumar.jpg', 'Ph.D. (2013), LUISS University, Rome', '011-26907557', 'B-207 (R&D Block)', 'https://iiitd.academia.edu/ManoharKumar', 'https://iiitd.ac.in/manohark', '["Moral and Political Philosophy","Applied Ethics","Civil Disobedience","Democratic Secrecy","Digital Ethics and Ethics of AI","Epistemic Injustice"]', '["Social and Political Philosophy","Applied Ethics","Moral Philosophy","Ethics of AI"]', '["Infosys Centre for Artificial Intelligence (CAI)","Ethics Lab","Academic Writing Lab"]', '[]', '2026-06-23 12:51:14.871', '2026-06-23 12:51:16.37713', '2026-06-23 12:51:14.871', 'Manohar Kumar has a PhD in Political Theory from LUISS University Rome and has held Postdoctoral positions at IIT Delhi and GREQAM, Aix Marseille University. He is the co-author with Daniele Santoro of Speaking Truth to Power. A Theory of Whistleblowing . He has also edited a book ''Social Scientists in the Civic Space. Ethical Perspectives on Democratic Involvement(with Arundhati Virmani and Jean Boutier). His works have appeared in Philosophy and Social Criticism, International Journal of Social Robotics, IEEE Transactions on Affective Computing, Critical Criminology, Law and Philosophy, IJCAI, Economic and Political Weekly, and in edited volumes of Routledge. He is currently a Principal Investigator of ''Political Theory of AI''.'),
  ('196', 'Manuj Mukherjee', 'manuj@iiitd.ac.in', 'Assistant Professor (ECE, Math)', 'ECE, Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/manuj.jpg', 'Ph.D. (2017), Indian Institute of Science, Bengaluru, India', '011-26907376', 'A-608 (R&D Block)', 'https://sites.google.com/view/manuj-mukherjee/home', 'https://iiitd.ac.in/manuj', '["Information Theory","Multiparty interactive communication","Interactive coding"]', NULL, NULL, '[]', '2026-06-23 12:51:15.2', '2026-06-23 12:51:16.720572', '2026-06-23 12:51:15.2', 'Dr. Manuj Mukherjee received his PhD from the Indian Institute of Science in 2017. Following his PhD, he did a couple of stints as a postdoc, at Telecom Paris, France, and at Bar Ilan University, Israel. He has regularly published in top tier journals and conferences of IEEE Information Theory Society. He is the recipient of the Seshagiri Kaikini Medal from the Electrical Communication Engineering department of the Indian Institute of Science for the best PhD thesis in the year 2017-2018. His research interests include the broad neighborhood of information theory in general.'),
  ('197', 'Md. Shad Akhtar', 'shad.akhtar@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/shad.jpg', 'Ph.D. (2019), IIT Patna, India', '011-26907365', 'B-407 (R&D Block)', 'http://faculty.iiitd.ac.in/~shad.akhtar/', 'https://iiitd.ac.in/shad', '["Sentiment Analysis","Emotion Analysis","Conversational Dialog Systems","Code-mixed Languages","Multimodal Analysis"]', '["Natural Language Processing","Deep Learning"]', NULL, '[]', '2026-06-23 12:51:15.494', '2026-06-23 12:51:17.006231', '2026-06-23 12:51:15.494', 'Md. Shad Akhtar completed his Ph.D. in Computer Science and Engineering from IIT Patna in 2019. He received his M.Tech from IIT (ISM), Dhanbad in 2014, and BEng from JMI, New Delhi, in 2009. He also has industry experience of more than two years with HCL Technologies Ltd. He has published research papers in various peer-reviewed conferences and journals of international repute. He has also served as the program committee member and reviewer for numerous international conferences and journals. His main areas of research are Sentiment and Emotion Analysis in the Natural Language Processing domain. Currently, his area of interest focuses on Dialog Management and Multimodal Analysis.'),
  ('198', 'Monika Arora', 'monika@iiitd.ac.in', 'Assistant Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/monika.jpg', 'Ph.D. (2018), Old Dominion University, Virginia, USA', '011-26907587', 'A-304 (R&D Block)', NULL, 'https://iiitd.ac.in/monika', '["Count data and statistical modeling"]', '["Statistical Inference","Categorical data","Stochastic Processes"]', NULL, '[]', '2026-06-23 12:51:15.794', '2026-06-23 12:51:17.31054', '2026-06-23 12:51:15.794', 'Monika Arora defended her Ph.D. thesis in Computational & Applied Mathematics from Old Dominion University, Virginia, USA in May 2018. She did her M.Sc. in Applied Statistics and Informatics (ASI) from Indian Institute of Technology (IIT), Bombay, India in May 2011. After her M.Sc. she worked for two years as a lead scientist in statistical modeling at a start up incubated by IIT-Bombay. Her current areas of research are count data and statistical modeling. She works on univariate and bivariate count models which are applied in various fields, e.g., health science, travel, insurance and ecology. Her research involves both theoretical and computational techniques to develop the models. She uses statistical softwares like R and SAS for her research.'),
  ('199', 'Mrinmoy Chakrabarty', 'mrinmoy@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/mrinmoy.jpg', 'Ph.D. (2017), Osaka University School of Medicine, Japan', '011-26907363', 'A-202 (R&D Block)', 'https://cogscience.wixsite.com/nigp', 'https://iiitd.ac.in/mrinmoy', '["Affective Cognitive Neuroscience","Visual-Spatial Cognition","Autism Spectrum Disorders","Decision Making","Learning-Memory","Anxiety Disorders"]', '["Learning and Memory","Decision Making"]', '["Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)"]', '[]', '2026-06-23 12:51:16.017', '2026-06-23 12:51:17.526775', '2026-06-23 12:51:16.017', 'Dr. Mrinmoy Chakrabarty completed his doctoral training with a fellowship from the Interdisciplinary Program for Biomedical Sciences of the Osaka University Graduate School of Medicine, Japan, earning his Ph.D. with Distinction. He was a Post-Doctoral Research Fellow for almost three years in the Dept. of Rehabilitation for Brain Functions at the National Rehabilitation Center for Persons with Disabilities, Japan [WHO Collaborating Center], before joining IIIT-Delhi. He has received further training in a) Neuroimaging and its Statistical analyses from the Faculty of Life Sciences & Medicine, King''s College London, and the Institute of Neurology, University College London, UK, respectively, and b) Computational Neuroscience from the University of Zurich and ETH Zurich, Switzerland. His present research employs psychophysics, psychophysiology, and neuroimaging with computational data analyses to study higher cognitive functions in humans.'),
  ('200', 'Mukesh Mohania', 'mukesh@iiitd.ac.in', 'Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/mukesh.jpg', 'Ph.D. (1995), Indian Institute of Technology - Bombay, India', '011-26907355', 'A-507 (R&D Block)', NULL, 'https://iiitd.ac.in/mukesh', '["Information Integration","Entity Discovery and Analytics","Big Data Analytics and Applications","Blockchain Data Management"]', '["Information Management and Data Integration"]', NULL, '[]', '2026-06-23 12:51:16.305', '2026-06-23 12:51:17.814884', '2026-06-23 12:51:16.305', 'Mukesh Mohania is a Professor at the Computer Science and Engineering department of IIIT Delhi. He has served as a Dean (Innovation, Research and Development) from July 2020 till June 2023 at IIITD. He is also a member of National Statistical Commission since December 2022. He received his Ph.D. in Computer Science & Engineering from Indian Institute of Technology - Bombay, India in 1995. He was a faculty member in University of South Australia and Western Michigan University from 1995-2001, and then worked at IBM Research (India and Australia) for 18+ years till October 2019 as Distinguished Engineer. His research interests are on Information (structured and unstructured data) integration, master data management, AI based entity analytics, big data analytics and applications, and blockchain data management. His work in these areas has led to the development of new products and also influenced several existing IBM products. He has received several awards within IBM, such as "Best of IBM", “Outstanding Innovation Award”, "Outstanding Technical Achievement Award", and many more. He has published more than 120 Research papers in reputed International Conferences and Journals and has more than 50 granted patents. He has held several visible positions in academia and professional activities, like Adjunct Professor at Australian National University and University of Melbourne, VLDB 2016 Conference Organising Chair, ACM India Vice-President (2015-2017), ACM Distinguished Service Award Committee Chair (2017-18), Distinguished Speaker Program Chair (2015-17), and editorial board member in several journals and transactions. He is an ACM Distinguished Scientist, a recipient of ACM Outstanding Service Award, and an IEEE Meritorious Award. He was a member of IBM Academy of Technology, and IBM Master Inventor.'),
  ('201', 'N. Arul Murugan', 'arul.murugan@iiitd.ac.in.', 'Associate Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/arulmurugan.jpg', 'Ph.D. (2005), Indian Institute of Science, Bangalore, India', '01126907372', 'A-311 (R&D Block)', 'https://iiitd.ac.in/arulmurugan', 'https://iiitd.ac.in/arulmurugan', '["ML and DL approaches for Druggability prediction","QM fragmentation based approaches for Druggability prediction","Parallel virtual screening in HPCs and GPUs for accelerated drugs discovery","Flexible docking assisted Drugs discovery","Atomistic simulation of virus-host cell interaction"]', '["Algorithms in Computational Biology","Cheminformatics"]', NULL, '[]', '2026-06-23 12:51:16.614', '2026-06-23 12:51:18.135725', '2026-06-23 12:51:16.615', 'Dr. N. Arul Murugan, is a Ph.D. from Solid State and Structural Chemistry unit at Indian Institute of Science, Bangalore, India). He was awarded a Ph.D. degree in the year 2005 for his thesis contribution entitled "Molecular simulations of temperature induced disorder and pressure induced ordering in organic molecular crystals." After Ph.D., he was on postdoctoral visits to various institutes in Europe such as ULB (Brussels, Belgium), KTH (Stockholm, Sweden) and UPC (Barcelona, Spain) until 2011, and his research stays were supported generously by the prestigious fellowships from Belgian national fund for scientific research (FNRS), Wenner-Gren foundation and Spanish Ministry of Science and Innovation (for Juan de La Cierva fellowship). From the year 2011, he was employed as a researcher at the School of Biotechnology, KTH Royal Institute of Technology and from 2015 he was appointed as a Docent (Associate Professor) in theoretical chemistry and Biology at the same school. He has been involved in teaching and supervision at KTH since the year 2013.  His research focuses on the computational development of drugs and PET tracers/optical probes for neurodegenerative diseases such as Alzheimer''s disease and Parkinson''s disease and infectious diseases including Covid-19. His research is also devoted to the development of QM and machine learning based approaches for druggability prediction. He has published about 120 articles in international peer-reviewed journals including Sci.Adv., PNAS, JACS, Biosens.& Bioelectron., JMedChem, JCTC, JPClett., He has also written 3 book chapters and edited a book.  He is serving as an editorial board member for Scientific Reports and IJMS and is currently editing a special issue on Covid-19 therapeutics and diagnostics for the IJMS journal.'),
  ('202', 'Nabanita Ray', 'nabanita@iiitd.ac.in', 'Assistant Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/nabanita.jpg', 'Ph.D. (2020), The Institute of Mathematical Sciences Chennai', '011-26907464', 'B-312 (R&D Block)', 'https://sites.google.com/view/nabanita-ray/home', 'https://iiitd.ac.in/nabanita', '["Positivity problems in Algebraic Geometry","Moduli problems of vector bundles over projective varieties","Moduli problem of co-dimension one cycles"]', '["Algebra","Analysis","Algebraic Geometry","Riemann Surface"]', NULL, '[]', '2026-06-23 12:51:16.922', '2026-06-23 12:51:18.43079', '2026-06-23 12:51:16.922', 'Nabanita Ray is a PhD degree holder from The Institute of Mathematical Sciences Chennai in 2020. She worked as a post-doctoral fellow in TIFR, Mumbai and CMI. Her general research interest is in Algebraic Geometry. She has published several research papers in national and international journals.'),
  ('203', 'Nikhil Gupta', 'nikhil@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/nikhil.jpg', 'Ph.D. (2022), Indian Institute of Science, Bangalore', '011-26907417', 'B-511 (R&D Block)', 'https://sites.google.com/view/nikhilgupta1', 'https://iiitd.ac.in/nikhil', '["Computational Complexity Theory","Derandomization","Algorithmic Number Theory"]', '["Computational Complexity Theory","Theory of Computation","Discrete Mathematics","Computational Algebra and Number Theory"]', NULL, '[]', '2026-06-23 12:51:17.231', '2026-06-23 12:51:18.744684', '2026-06-23 12:51:17.231', 'Dr. Nikhil Gupta earned his Ph.D. from the Indian Institute of Science, Bangalore, in 2022 under the guidance of Prof. Chandan Saha. After that, he worked as a postdoc at Boston College with Prof. Ilya Volkovich. He obtained his M.Sc. (Engineering) in computer science from the Indian Institute of Science in 2017 and his B.Tech. in computer science from Maharishi Markandeshwar University, Mullana, in 2015. He taught an undergraduate course on discrete mathematics and the theory of computation in spring 2022 at Boston College. He co-organized computer science research seminars at Boston College in 2023–2024.'),
  ('204', 'Nishad Patnaik', 'nishad@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/nishad.jpg', 'Ph.D. (2013), NSSR, New York, USA', '011-26907364', 'A-205 (R&D Block)', NULL, 'https://iiitd.ac.in/nishad', '["Kantian transcendental Idealism","Husserlian phenomenology","Social and Political Philosophy"]', '["Kantian transcendental Idealism","Husserlian phenomenology","Social and Political Philosophy"]', NULL, '[]', '2026-06-23 12:51:17.552', '2026-06-23 12:51:19.068063', '2026-06-23 12:51:17.552', 'Nishad received his PhD in philosophy from The New School for Social Research (NSSR), New York, U.S.A in 2013. He holds a M.A. in philosophy from NSSR, as well as a M.A. and M.Phil. in philosophy from Delhi University. His dissertation entitled, “Time, Space and Finitude; Kant and Husserl on the Question of Transcendental Logic” received the ‘Alfred Schutz Memorial Award in Philosophy and Sociology’. In addition to his research interests in Kantian transcendental Idealism, and Husserlian phenomenology, Nishad’s other areas of research include Social and Political Philosophy, Marx and the Critical Theory tradition, Ethics, and the Philosophy of Technology. He is currently engaged in writing a book length manuscript on the genealogy of nationalist identity and its apparently paradoxical reassertion in the context of the hegemony of the contemporary capitalist world order. Before joining IIITD, he was a visiting assistant professor at IIIT Hyderabad (2018-19), Visiting Fellow at J.N.U. (2015-17), and held visiting faculty positions at IIT Delhi (2015-16), St. Stephen’s College, Delhi (2016-17) and Westchester Community College, New York, 2013-14.'),
  ('205', 'Ojaswa Sharma', 'ojaswa@iiitd.ac.in', 'Associate Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/ojaswa.jpg', 'Ph.D. (2010), Technical University of Denmark, Denmark', '011-26907476', 'A-511 (R&D Block)', 'http://faculty.iiitd.ac.in/~ojaswa/', 'https://iiitd.ac.in/ojaswa', '["Computer graphics and geometry with focus on Virtual and Mixed reality (VR/MR)","Volume rendering","3D reconstruction","High performance computing on GPU"]', '["Computer graphics and geometry with focus on Virtual and Mixed reality (VR/MR)","Volume rendering","3D reconstruction","High performance computing on GPU"]', '["Graphics Research Group (GRG)","Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)"]', '[]', '2026-06-23 12:51:17.848', '2026-06-23 12:51:19.365741', '2026-06-23 12:51:17.848', 'Ojaswa Sharma is an associate professor at the Indraprastha Institute of Information Technology Delhi. He completed his Ph.D. in Mathematics and Computer Science from the Technical University of Denmark, Denmark. He has more than four years of experience with corporate R&D. His research spans various aspects of Computer Graphics, and Computational Geometry. In particular his work focuses on Geometry creation and reconstruction, Virtual/Augmented Reality (AR/VR), and volume visualization. He leads the Graphics Research Group (GRG) at IIIT-Delhi.'),
  ('206', 'Paro Mishra', 'paro.mishra@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/paro.jpg', 'Ph.D. (2017), IIT Delhi, India', '011-26907570', 'B-209 (R&D Block)', 'https://sites.google.com/iiitd.ac.in/paromishra/home', 'https://iiitd.ac.in/paro', '["Gender and Technology","New reproductive Technologies","Digital Technologies","Demographic Anthropology","Intimate Relations","Migration and Transnationalism"]', '["Enhancement Technologies and Body","Contemporary Indian Society","Digital Intimacy","Gender Studies, Migration and Transnationalism"]', '["Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)"]', '[]', '2026-06-23 12:51:18.149', '2026-06-23 12:51:19.663152', '2026-06-23 12:51:18.149', 'Paro received her Ph.D. from the Department of Humanities and Social Sciences, Indian Institute of Technology, Delhi in 2017. Her core research interests lie at the intersection of Gender and Technology – New Reproductive Technologies (NRTs) and Information/ Digital Technologies, in particular. She has published on intimate migrations, masculinity, aging, care circulation, care work and gendered surveillance. Paro has received several fellowships and grants from the Netherlands Institute for Advanced Studies, University Grants Commission, IIT Delhi and the Indian Council of Social Science Research. She has recently finished a project on sex-selective technologies, male marriage squeeze and cross-cultural intimacies funded by the Indian Council of Social Science Research (2018). Her current research is examining intersections of Gender, Health and Digital Technologies with a focus on emerging FemTech Landscape in India. This project is funded by IIITD-IITD MFIRP Scheme. Select publications include special issues co-editorship for Asian Bioethics Review (2021) and Asian Journal of Women''s Studies and in Journals like Anthropology and Aging, The Sociological Review, Economic & Political Weekly, and Society and Culture in South Asia.'),
  ('207', 'Piyus Kedia', 'piyus@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/piyuskedia.jpg', 'Ph.D. (2018), IIT Delhi, India', '011-26907528', 'B-505 (R&D Block)', 'https://piyus.github.io/', 'https://iiitd.ac.in/piyus', '["System security, safe languages, virtualization and dynamic/static techniques to build systems"]', '["System security, safe languages, virtualization and dynamic/static techniques to build systems"]', NULL, '[]', '2026-06-23 12:51:18.47', '2026-06-23 12:51:19.990829', '2026-06-23 12:51:18.47', 'Piyus Kedia is an assistant professor at IIIT Delhi. He received his Ph.D. from IIT Delhi. He works in the area of programming languages and systems security. His research work appeared at conferences ISSTA, OOPSLA, EuroSys, etc.'),
  ('208', 'Pragma Kar', 'prgama@iiitd.ac.in', 'Assistant Professor (HCD)', 'HCD', 'https://iiitd.ac.in/sites/default/files/images/faculty/pragma.jpg', 'Ph.D. (2023), Jadavpur University', '011-26907450', 'A-411 (R&D Block)', NULL, 'https://iiitd.ac.in/pragma', '["Ubiquitous Computing","Human-Computer Interaction","Sensing"]', '["Ubiquitous Computing","Human-Computer Interaction","Sensing"]', NULL, '[]', '2026-06-23 12:51:18.771', '2026-06-23 12:51:20.280562', '2026-06-23 12:51:18.771', 'Dr. Pragma Kar completed her Ph.D. with the prestigious DST-INSPIRE fellowship at Jadavpur University in 2023. She earned her M.Tech degree from Jadavpur University in 2016, where she was honored with the University Gold Medal for achieving the highest academic distinction in her department. Dr. Kar''s research interests encompass, but are not limited to, Ubiquitous Computing, Human-Computer Interaction, and Sensing. During her doctoral studies, she focused on the development and evaluation of innovative assistive systems aimed at enhancing the quality and inclusivity of online education. Her research has been presented at prestigious conferences such as CSCW, MobileHCI, and CHI, among others. Dr. Kar has received numerous accolades, including the Honorable Mention at EICS 2020, the Gary Marsden Travel Award, the Computer Engineering Division Prize (JTIE), the Outstanding Service and Best Poster First Runners-Up Award at COMSNETS 2023, and the Excellence in Review Award at MobileHCI 2023.'),
  ('209', 'Pragya Kosta', 'pragya@iiitd.ac.in', 'Assistant Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/pragya.jpg', 'Ph.D. (2020), University of Utah', '011-26907491', 'B-607 (R&D Block)', 'https://sites.google.com/view/witty-lab/about-us', 'https://iiitd.ac.in/pragya', '["Implantable and wearable technologies","Wireless power transfer for biomedical applications","Neural stimulation and neurotechnology","Bio-electromagnetics","AI for healthcare"]', '["Circuit Theory and Devices","Neural Engineering and Implantable Devices"]', '["Wearable, Implantable Technologies & Systems Lab (Witty Lab)"]', '[]', '2026-06-23 12:51:19.078', '2026-06-23 12:51:20.583638', '2026-06-23 12:51:19.078', 'Pragya Kosta is a researcher in the areas of implantable, wearable technologies, neurotechnology, and bio-electromagnetics. She obtained a Ph.D. in Electrical and Computer Engineering from the University of Utah, USA, in 2020 under the guidance of Dr. Gianluca Lazzi. After that, she worked as a postdoctoral researcher at the Institute for Technology and Medical Systems Innovation (ITEMS), University of Southern California. During her Ph.D. and postdoc, she collaborated with pioneering neurotechnology companies like Alfred Mann Foundation (now known as huMannity Medtec) and Second Sight Medical Products (now known as Cortigent). She has published several papers at well-known venues such as Scientific Reports, IEEE TBME, IEEE TNSRE, IEEE J-ERM, IEEE TAP, and IEEE EMBC. She completed her M.Tech. in ECE from IIT Roorkee and her B.Tech. in ECE from IIIT Jabalpur. She received multiple academic awards during her undergraduate studies, including the JENESYS (Japan-East Asia Network of Exchange for Students and Youths) fellowship. She is passionate about developing innovative medical technologies for improving the quality of life.'),
  ('210', 'Prahllad Deb', 'prahllad@iiitd.ac.in', 'Assistant Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/prahllad.jpg', 'Ph.D. (2020), Indian Institute of Science Education and Research Kolkata', '011-26907551', 'B-305 (R&D Block)', '#', 'https://iiitd.ac.in/prahllad', '["Free noncommutative (NC for short) function theory","Homogeneous Cowen-Douglas operators and differential geometry"]', '["Real and complex analysis","Linear algebra","Representation theory of finite groups","Functional analysis and Operator theory","Differential geometry and topology","Algebraic topology","Geometric group theory","Complex geometry","Noncommutative analysis"]', NULL, '[]', '2026-06-23 12:51:19.377', '2026-06-23 12:51:20.883194', '2026-06-23 12:51:19.377', '["Prahllad Deb is currently a faculty member at IIIT Delhi. Prior to joining IIITD, he was a postdoctoral fellow in the Department of Mathematics at Ben-Gurion University of the Negev, Israel. He earned his Ph.D. in 2020 from the Indian Institute of Science Education and Research (IISER) Kolkata, following an M.S. degree from the Indian Institute of Science (IISc), Bengaluru, and a B.Sc. degree from Jadavpur University.","His research interests broadly lie in functional analysis, complex analysis, and multivariate operator theory. More specifically, he works on the analytic and geometric structure of free noncommutative (NC) analytic functions and their deep connections with multivariate operator theory. He is also keen on expanding his research program into complex differential geometry and metric geometry.","The major themes of his current research include free noncommutative function theory, homogeneous Cowen–Douglas operators, and differential geometry and topology.","Beyond mathematics, Prahllad enjoys playing table tennis, cooking, and travelling, finding these pursuits a refreshing complement to his academic life."]'),
  ('211', 'Praveen Priyadarshi', 'praveen@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/praveen.jpg', 'Ph.D. (2018), London School of Economics and Political Science, London', '011-26907359', 'A-203 (R&D Block)', 'https://www.urbanpublics.space/praveen', 'https://iiitd.ac.in/praveen', '["Distinctiveness of everyday political practices in new urban spaces"]', '["Smart Cities","Urban Politics","Indian Democracy"]', NULL, '[]', '2026-06-23 12:51:19.689', '2026-06-23 12:51:21.210652', '2026-06-23 12:51:19.689', 'Dr. Praveen Priyadarshi completed his Ph.D. in Development Studies from London School of Economics and Political Science (LSE), London. His academic interest lies at the intersections of the categories of space, institutions and policy especially in the urban context. He brings these categories to bear upon his understanding of contemporary politics in India and the Global South. Before joining us, Praveen has been an Assistant Professor in the Department of Political Science, Zakir Husain Delhi College, Evening, University of Delhi (DU). His publications include papers in Economic and Political Weekly (EPW) and a co-edited book from Pearson Longman, titled Contemporary India: Economy, Society, Politics. He has been an Associate at the Crisis States Research Centre, LSE, and at the Developing Countries Research Centre (DCRC), University of Delhi. He was the Tata Ph.D. Fellow at the Asia Research Centre (ARC), at the London School of Economics.'),
  ('212', 'Pravesh Biyani', 'praveshb@iiitd.ac.in', 'Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/pravesh.jpg', 'Ph.D. (2012), IIT Delhi, India', '011-26907449', 'A-604 (R&D Block)', 'https://chartrmobility.gitlab.io/pravesh/', 'https://iiitd.ac.in/praveshb', '["Optimisation for signal processing and communications","Machine learning, and transportation."]', '["Signal Processing","Optimisation","Communications."]', NULL, '[]', '2026-06-23 12:51:19.994', '2026-06-23 12:51:21.5081', '2026-06-23 12:51:19.994', 'Pravesh Biyani was born in Raigarh, India and received my B.Tech from IIT Bombay in 2002 and MS from McMaster University in the year 2004. I have also worked at the Ikanos Communications while pursuing my Ph.D. at the IIT Delhi till early 2012. In the later 2012, I was a post- doctoral researcher at the University of Minnesota, Minneapolis with Prof. Tom Luo. I have won the INSPIRE Faculty award by the Govt. of India in 2012 and am currently an INSPIRE faculty at the IIIT Delhi. My research interests are physical layer wireless and wireline communications, optimization for signal processing and machine learning. Recently I have developed interest in applying ideas from Convex Optimization in solving problems in urban transportation, specially the bus route network design problem.'),
  ('213', 'Pushpendra Singh', 'psingh@iiitd.ac.in', 'Head (CSE),
Professor (CSE, HCD)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/puspendra.jpg', 'Ph.D. (2004), Inria-Rennes, University de Rennes 1, France', '011-26907458', 'A-502 (R&D Block)', 'https://www.pushpendrasingh.info', 'https://iiitd.ac.in/pushpendra', '["Mobile Systems and Applications","Middleware","ICT for Development"]', '["Operating Systems","Computer Networks","Mobile Computing."]', NULL, '[]', '2026-06-23 12:51:20.298', '2026-06-23 12:51:21.8165', '2026-06-23 12:51:20.298', '["Pushpendra Singh is a Professor and Head of the Department of Computer Science and Engineering at the Indraprastha Institute of Information Technology Delhi (IIIT-Delhi), where he is also a founding faculty member. He has held major academic leadership roles at IIIT-Delhi, including Dean (Academic Affairs) and Dean (Innovation, Research, and Development). He received his Ph.D. in 2004 from Inria-Rennes, France, in the area of mobile computing. Prior to joining IIIT-Delhi, he worked at the University of Portsmouth, Newcastle University, and Inria-Rocquencourt. His research lies at the intersection of human–AI interaction, mobile systems and applications, middleware, FemTech, and ICT for Development, with a strong emphasis on building scalable, robust, and field-deployable socio-technical systems. His work combines core systems research with applied, impact-driven deployments, particularly in resource-constrained and real-world environments. A key focus of his research is translating academic innovation into practice, with several outcomes leading to industry transfer, start-ups, and deployed products. His technologies have been deployed in large-scale public-sector and government initiatives, including national programs such as the National Rural Health Mission (NRHM) and the National Rural Employment Guarantee Scheme (NREGS).","He was also appointed as the Nodal Officer by the Government of NCT of Delhi for the 181 Women-in-Distress Helpline, for which his team architected, developed, and deployed the complete software platform. His technologies have been deployed in large-scale public-sector and government initiatives, including national programs such as the National Rural Health Mission (NRHM) and the National Rural Employment Guarantee Scheme (NREGS). He was also appointed as the Nodal Officer by the Government of NCT of Delhi for the 181 Women-in-Distress Helpline, for which his team architected, developed, and deployed the complete software platform. Prof. Singh has an extensive track record of national and international research collaboration. He is actively interested in international research collaborations, particularly in areas spanning human-centered AI, digital health, FemTech, mobile and edge systems, and technology for social impact."]'),
  ('214', 'Rajiv Raman', 'rajiv@iiitd.ac.in', 'Associate Professor (CSE, Math)', 'CSE, Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/rajiv.jpg', 'Ph.D. (2007), University of Iowa, USA', '011-26907573', 'B-507 (R&D Block)', 'https://rajivraman.weebly.com/', 'https://iiitd.ac.in/rajiv', '["Algorithms","Combinatorial Optimization","Graph Theory","discrete and computational geometry"]', '["Algorithms","Discrete mathematics","Optimization","Graph theory"]', NULL, '[]', '2026-06-23 12:51:20.621', '2026-06-23 12:51:22.128176', '2026-06-23 12:51:20.621', 'Prof. Rajiv Raman is a faculty at IIIT-Delhi since 2012. His primary area of research is algorithms. He is interested in the design and analysis of algorithms for problems in various domains such as scheduling, resource allocation, graph colouring and geometry. He also has an interest in the development of efficient practical heuristics for real-life problems. He obtained his PhD degree in Computer Science from the University of Iowa in 2007. Since then, he has worked as a postdoctoral fellow at the Max-Planck institute for informatics in Germany, and at the Centre for Discrete Mathematics and Applications at the University of Warwick. He has also worked briefly at TCS Innovation Labs before joining IIIT in 2012.'),
  ('215', 'Rajiv Ratn Shah', 'rajivratn@iiitd.ac.in', 'Associate Professor (CSE, HCD)', 'CSE, HCD', 'https://iiitd.ac.in/sites/default/files/images/faculty/ratn.jpg', 'Ph.D. (2017),  National University of Singapore, Singapore', '011-26907495', 'A-409 (R&D Block)', 'http://midas.iiitd.edu.in', 'https://iiitd.ac.in/rajivratn', '["Multimodal semantic and sentiment analysis of user-generated social media content","NLP","Speech Processing","Computer Vision","Multimodal Computing"]', '["Deep learning based multimedia systems","Information Retrieval","HCI, Multimedia Content Analysis"]', '["Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)"]', '[]', '2026-06-23 12:51:20.922', '2026-06-23 12:51:22.444017', '2026-06-23 12:51:20.922', 'Rajiv Ratn Shah received his Ph.D. in computer science from the National University of Singapore, Singapore. Prior completing his Ph.D., he received his M.Tech. and MCA degrees in computer applications from the Delhi Technological University, Delhi and Jawaharlal Nehru University, Delhi, respectively. He has also received his BSc in Mathematics (Honors) from the Banaras Hindu University, Varanasi. Dr Shah is the recipient of several awards, including the prestigious European Research Consortium for Informatics and Mathematics (ERCIM) Fellowship and runner-up in the Grand Challenge competition of ACM International Conference on Multimedia. He is involved in organizing and reviewing of many top-tier international conferences and journals. After joining IIITD in Dec 2016, he has spent 1 year as a Research Fellow in Living Analytics Research Center (LARC) at the Singapore Management University, Singapore.'),
  ('216', 'Ram Krishna Ghosh', 'rkghosh@iiitd.ac.in', 'Associate Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/rkghosh.jpg', 'Ph.D. (2013), Indian Institute of Science, Bangalore', '011-26907367', 'B-601 (R&D Block)', 'https://qelab.iiitd.ac.in/', 'https://iiitd.ac.in/rkghosh', '["Computational nanoelectronics, spintronics, quantum transport simulation, device modeling, materials modeling, and multiscale modeling"]', '["Electronics, Semiconductor Device Physics, Nanoscale Devices, Advanced CMOS and beyond CMOS Devices, Quantum Materials and Devices, etc."]', '["Quantum Electronics Lab"]', '[]', '2026-06-23 12:51:21.21', '2026-06-23 12:51:22.718413', '2026-06-23 12:51:21.21', 'Dr. Ram Krishna Ghosh obtained his Ph.D. from the Department of Electronic Systems Engineering, Indian Institute of Science, Bangalore in 2013. He has experience in computational nanoelectronics, particularly in the area of ''materials-devices co-design'' of next-generation CMOS and beyond CMOS computing. He has worked as a post-doctoral fellow at the Pennsylvania State University and the University of Notre Dame, USA. He has been a DST Inspire Faculty at the Jawaharlal Nehru University, New Delhi, before joining IIIT-Delhi. He is the recipient of the Best Ph.D. thesis award (Tag Corporation Medal) from the Council of Indian Institute of Science, Bangalore. He is also a recipient of Inspire Faculty Award from DST and the Early Career Research Award from SERB. His current research interests include computational materials design (primarily, ab-initio Density Functional Theory and Molecular Dynamics simulations), quantum transport simulations, and multiscale modeling of emerging electronic, spintronic, and photovoltaic devices.'),
  ('217', 'Ravi Anand', 'ravi.anand@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/ravianand.jpg', 'Ph.D. (2021), IIT Kharagpur', '011-26907466', 'A-503 (R&D Block)', '#', 'https://iiitd.ac.in/ravianand', '["Classical and quantum cryptanalysis of symmetric ciphers","Design of symmetric Ciphers"]', '["Cryptography - Classical and Quantum","Quantum Computing","Cryptanalysis"]', NULL, '[]', '2026-06-23 12:51:21.424', '2026-06-23 12:51:22.93674', '2026-06-23 12:51:21.424', 'Dr. Ravi Anand earned his Ph.D. from IIT Kharagpur in 2021 where he was part of the Cryptology Research Group under the supervision of Prof. Sourav Mukhopadhyay. Following that, he completed postdoctoral research at ISI Kolkata under Prof. Subhamoy Maitra, and later at the University of Hyogo under Prof. Takanori Isobe .His primary research interests lie in the cryptanalysis of symmetric ciphers, spanning both classical as well as quantum framework. He is also involved in the design of lightweight and secure symmetric primitives. More recently, he has started exploring the application of machine learning techniques to the cryptanalysis of symmetric ciphers.'),
  ('218', 'Richa Gupta', 'richa.gupta@iiitd.ac.in', 'Assistant Professor (HCD)', 'HCD', 'https://iiitd.ac.in/sites/default/files/images/faculty/richagupta.jpg', 'Ph.D. (2020), IIT Delhi, India', '011-26907368', 'A-406 (R&D Block)', '#', 'https://iiitd.ac.in/richagupta', '["Perceptual foundations of Design","Inclusive Design and Accessibility","Metaverse","HCI","Interaction Design","Educational Technologies"]', '["Product Design & Prototyping","Inclusive Design & Accessibility","Design for Special Needs","Fundamentals of Design","Interaction Design"]', '["Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)","Accessibility and Inclusive Design (AID) Lab","Centre for Sustainable Mobility (CSM)"]', '[]', '2026-06-23 12:51:21.733', '2026-06-23 12:51:23.246698', '2026-06-23 12:51:21.733', 'Dr. Richa Gupta completed her Ph.D. from IIT Delhi in 2020. She holds a post-graduate degree in Industrial Design (M.Des.) from IDC, IIT Bombay (2013) and completed B.Tech. in Mechanical Engineering from IIIT Jabalpur (2011). She has done collaborative research at the School of Informatics and Computing, IUPU Indianapolis, USA (2017-18) and TU Darmstadt, Germany (2012). She was also invited at Nagasaki University as Visiting Professor in 2024. She has received the NCPEDP Mphasis Universal Design Award 2025 and Neilom Prize 2021 for her contributions in research, knowledge dissemination and product development in the domain of Accessibility and Inclusive Design for enabling access to education, information and spaces for persons with special needs. She has also worked as Project Scientist at AssisTech Labs, IIT Delhi where she contributed in design and development of several award winning translational research projects, namely SmartCane Device, DotBook (Braille Laptop for Blind), TacRead, OnBoard Bus Identification System, Accessible Graphics Design, and Multi-Modal Braille Learning Device. She is recipient of several prestigious fellowships namely, Stanford Ignite Global Innovation Fellowship (2015), Visvesvaraya PhD Fellowship (2015), JENESYS Fellowship (Indo-Japan Exchange Program, 2010). She was awarded the Chairman’s Silver Medal for Excellence in Academics at IIIT Jabalpur in 2011. Her current research interests are: Perceptual foundations of Design, Inclusive Design and Accessibility, Product Design & Modern Prototyping, Multi-modal Interaction/Experience Design'),
  ('219', 'Rinku Shah', 'rinku@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/rinku.jpg', 'Ph.D. (2021), IIT Bombay, India', '011-26907538', 'B-502 (R&D Block)', 'https://faculty.iiitd.ac.in/~rinku/', 'https://iiitd.ac.in/rinku', '["Software-Defined Networking","Data plane programming","4G/5G mobile networks"]', '["Computer networks","Programmable networks"]', NULL, '[]', '2026-06-23 12:51:22.041', '2026-06-23 12:51:23.56097', '2026-06-23 12:51:22.042', 'Dr. Rinku Shah earned her Ph.D. degree in Computer Science from IIT Bombay in February 2021. She has worked with Prof. Mythili Vutukuru and Prof. Purushottam Kulkarni at IIT Bombay. During her Ph.D., she interned at VMware for six months towards defining and solving capacity-aware load balancing in data center networks. After her Ph.D., she has spent seven months as a Project Research Scientist on a Huawei project at IIT Bombay with Prof. Umesh Bellur. Her primary research interests lie in the broad area of networked systems, specifically Software-Defined Networking (SDN) and programmable data planes. Her focus is to design data plane algorithms and data structures to build flexible, scalable, and fault-tolerant systems that solve real-world problems. Her research is published at reputed conference venues such as the ACM SOSR, IEEE ICNP, ACM APNet, and the ACM DEBS. She has served as a reviewer for peer-reviewed conferences such as EuroSys (shadow PC member), ICACCI, and INDICON.'),
  ('220', 'Ruhi Sonal', 'ruhi@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/ruhi.jpg', 'Ph.D. (2020), IIT Delhi, India', '011-26907556', 'A-211 (R&D Block)', 'https://sites.google.com/view/ruhisonal/home', 'https://iiitd.ac.in/ruhi', '["Discrete Choice Models","Network Formation Games","Optimal Stopping Problems"]', '["Game Theory","Microeconomics","Decision Theory"]', NULL, '[]', '2026-06-23 12:51:22.349', '2026-06-23 12:51:23.856228', '2026-06-23 12:51:22.349', 'Ruhi Sonal is an economic theorist who works primarily in the areas of decision theory and game theory. She completed her PhD from IIT Delhi in 2020 and her work has been published in leading journals in economics. While her research interests are varied, she specializes in modeling boundedly rational agents in different economic settings. Prior to joining IIIT Delhi, she worked as an Assistant Professor at IIT Jodhpur.'),
  ('221', 'Sachchidanand Prasad', 'sachchidanand@iiitd.ac.in', 'Assistant Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/sachchidanand.jpg', 'Ph.D. (2022), IISER Kolkata', '011-26907554', 'B-301 (R&D Block)', 'https://prasadsachchidanand.github.io/', 'https://iiitd.ac.in/sachchidanand', '["(1) Differential Geometry (Cut and focal locus in Reimannian and Finsler geometry)","(2) Morse-Bott functions","(3) Algebraic Topology","(4) Graph Theory"]', '["(1) Differential geometry and topology","(2) Algebraic topology","(3) Real and complex analysis","(4) Lie algebra and Lie groups","(5) Riemannian geometry","(6) Abstract Algebra"]', NULL, '[]', '2026-06-23 12:51:22.659', '2026-06-23 12:51:24.167933', '2026-06-23 12:51:22.659', 'Dr. Sachchidanand Prasad is a Ph.D. degree holder from IISER Kolkata in 2022 under the supervision of Prof. Somnath Basu. Following his doctoral studies, he spent nearly a year at the International Centre for Theoretical Sciences (ICTS-TIFR) as a postdoctoral fellow. He then joined Jilin University, China, and the University of Göttingen, Germany, as a Dingxin Scholar (at Jilin University), working with Prof. Thomas Schick. His primary research interests lie in algebraic topology and differential geometry, with a focus on Riemannian and Finsler geometry. Specifically, he studies the cut locus and focal locus of submanifolds in various geometric settings. In addition to his work in geometry, he also has interests in graph theory and non-commutative algebra.'),
  ('222', 'Saket Anand', 'anands@iiitd.ac.in', 'Associate Professor (CSE, ECE)', 'CSE, ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/saket.jpg', 'Ph.D. (2013), Rutgers University, NJ, USA', '011-26907425', 'B-410 (R&D Block)', 'http://faculty.iiitd.ac.in/~anands/', 'https://iiitd.ac.in/anands', '["Geometric Computer Vision","Semi-supervised learning","Robust methods","Scene understanding"]', '["Computer Vision","Statistical Signal Processing","Machine Learning","Linear optimization"]', NULL, '[]', '2026-06-23 12:51:22.888', '2026-06-23 12:51:24.39908', '2026-06-23 12:51:22.888', 'Saket Anand is an Associate Professor at Indraprastha Institute of Information Technology (IIIT), Delhi. He completed his PhD in Electrical and Computer Engineering from Rutgers University in 2013. He was part of the Robust Image Understanding Lab at Rutgers and his current research interests are design of robust statistical methods for heavily corrupted data, 3D scene reconstruction techniques and semi-supervised clustering methods. From 2007 to 2010, he worked as a research engineer at Read-Ink Technologies, Bangalore, developing algorithms for handwriting recognition. His Masters research carried out at Rutgers (2004-2006) involved design and implementation of face recognition and speech recognition algorithms. He is a member of the IEEE.'),
  ('223', 'Sambuddho Chakravarty', 'sambuddho@iiitd.ac.in', 'Associate Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/sambuddho.jpg', 'Ph.D. (2014), Columbia University, USA', '011-26907478', 'B-503 (R&D Block)', 'https://sambuddho.github.io/', 'https://iiitd.ac.in/sambuddho', '["Network Anonymity and Privacy","Network Censorship and Anti-Censorship","Network and Systems Security"]', '["Network Anonymity and Privacy (NAP 7XX)","Network Security","Host/Systems Security","OS","Computer Network"]', NULL, '[]', '2026-06-23 12:51:23.167', '2026-06-23 12:51:24.681421', '2026-06-23 12:51:23.167', 'Sambuddho Chakravarty completed his Ph.D. in Computer Science from Columbia University in 2014. He was advised by Prof. Angelos D. Keromytis. His research focuses on Network Anonymity and Privacy, Network Surveillance and Anti-Censorship and Network and Distributed Systems Security in general. During his Ph.D. he studied novel practical traffic analysis vulnerabilities of popular anonymity networks like Tor. He has served an intern at Telcordia Applied Research, New Jersey and Force 10 Networks, California.'),
  ('224', 'Sanat K Biswas', 'sanat@iiitd.ac.in', 'Associate Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/sanatk.jpg', 'Ph.D. (2017), University of New South Wales', '011-26907439', 'B-602 (R&D Block)', 'https://ssl.iiitd.edu.in/author/sanat-k-biswas/', 'https://iiitd.ac.in/sanat', '["Space vehicle guidance","Navigation and control","Orbit determination","GNSS-based navigation, non-linear dynamics and estimation algorithms"]', '["Circuits and Signals","Digital Signal Processing","Linear Control System and State Space Methods","Optimal Control and Estimation","Global Navigation Satellite System (GNSS)"]', NULL, '[]', '2026-06-23 12:51:23.402', '2026-06-23 12:51:24.912649', '2026-06-23 12:51:23.402', 'Sanat holds Ph.D. (2017) in space vehicle navigation from the University of New South Wales, M. Tech (2012) in Aerospace Engineering from IIT Bombay and B.E. (2010) in Instrumentation and Electronics Engineering from Jadavpur University. Sanat''s research interests include space vehicle guidance, navigation and control, orbit determination, GNSS-based navigation, non-linear dynamics and estimation algorithms. Sanat was associated with the Australian Centre for Space Engineering Research, where he did his PhD research. He also participated in the development of a nano satellite, UNSW-EC0 which was recently launched into a Low Earth Orbit. He received 2014 Emerging Space Leaders'' Grant from the International Astronautical Federation for his research contribution in space engineering.'),
  ('225', 'Sanjit Krishnan Kaul', 'skkaul@iiitd.ac.in', 'Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/sanjit.jpg', 'Ph.D. (2011), Rutgers University, USA', '011-26907457', 'B-411 (R&D Block)', 'http://faculty.iiitd.ac.in/~skkaul/', 'https://iiitd.ac.in/skkaul', '["Age-of-Information","Networking for Cyber Physical Systems","Networks of Autonomous Vehicles, and Autonomous Driving"]', '["Probability and Random Processes","Wireless Networks","Reinforcement Learning"]', NULL, '[]', '2026-06-23 12:51:23.687', '2026-06-23 12:51:25.210091', '2026-06-23 12:51:23.687', 'Sanjit K. Kaul received the B.Tech. degree in electronics and communications engineering from the Birla Institute of Technology, Mesra, in 2000 and the Ph.D. degree in electrical and computer engineering from Rutgers University in 2011. Year 2000 onwards, he worked in the telecommunications industry for four years. He was a Research Assistant with the Wireless Information Networks Laboratory from 2005 to 2011. He is currently an Professor with IIIT-Delhi. He works on problems in wireless systems research. His current interests include age-of-information, networking for cyber-physical systems, networks of autonomous vehicles, and autonomous driving.'),
  ('226', 'Sankha S Basu', 'sankha@iiitd.ac.in', 'Assistant Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/sankhasbasu.jpg', 'Ph.D. (2013), The Pennsylvania State University', '011-26907489', 'B-306 (R&D Block)', NULL, 'https://iiitd.ac.in/sankha', '["Mathematical Logic - intuitionistic logic and paraconsistent logics"]', '["Mathematical Logic"]', NULL, '[]', '2026-06-23 12:51:23.984', '2026-06-23 12:51:25.506281', '2026-06-23 12:51:23.984', 'Sankha has obtained his Ph.D. in Mathematics from The Pennsylvania State University in 2013, and an M.S. in Mathematics from Marquette University in 2008. His area of research is Mathematical Logic. More specifically, his area of interest is in non-classical logics, such as intuitionistic logic and paraconsistent logics. His Ph.D. dissertation links intuitionistic logic with computability theory via a model for higher-order intuitionistic logic that is based on the Turing degrees. Before joining IIIT-Delhi, he worked as faculty at The Pennsylvania State University, the University of Tennessee at Chattanooga, and Middle Tennessee State University.'),
  ('227', 'Sarthok Sircar', 'sarthok@iiitd.ac.in', 'Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/sarthoks.jpg', 'Ph.D. (2009), University of South Carolina.', '011-26907435', 'B-303 (R&D Block)', 'https://faculty.iiitd.ac.in/~sarthok', 'https://iiitd.ac.in/sarthok', '["Developing multiscale models and robust numerical algorithms for complex systems.","Fluid Mechanics","Aymptotics and perturbations"]', '["Integral Transforms and Fractional Calculus","Variational calculus and their applications","Multivariate Calculus","Variational Calculus","Fractional Calculus","Approximation theory"]', NULL, '[]', '2026-06-23 12:51:24.295', '2026-06-23 12:51:25.801967', '2026-06-23 12:51:24.295', 'Dr. Sarthok Sircar was a Lecturer- School of Mathematical Sciences at the Adelaide University-Australia. He has completed his PhD in 2009 in Applied Mathematics from University of South Carolina followed by postdoctoral fellowships in University of Colorado and University of Utah in USA. In the past 12 years of his scholastic work in the field of Applied Mathematics, he has applied multi-scale modeling, numerical simulations and experimental design to solve complex problems viz. dynamics and rheology of active gel systems, bacterial swarming and aggregation, swelling kinetics of ionic gels and liquid crystals polymers. His research work has been published in the form of peer reviewed journal articles (25), book chapters (1), guest lectures (20) and conference proceedings (1). His work has obtained 300+ citations with h-index of 10 and i-index of 10. He has taught courses in Calculus, Differential Equations, Linear Algebra, Calculus of Variations, Optimization and Mathematical Biology.'),
  ('228', 'Satish Kumar Pandey', 'satish@iiitd.ac.i', 'Assistant Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/satish.jpg', 'Ph.D. (2018), University of Waterloo, Canada', '011-26907369', 'A-206 (R&D Block)', 'http://noncommutative.space/', 'https://iiitd.ac.in/satish', '["Operator theory (univariate and multivariate)","Operator algebras","Reproducing kernel Hilbert spaces","Quantum information theory"]', '["(Advanced) Linear algebra","Point-set topology","Real and complex analysis","Functional analysis","Quantum information theory","Reproducing kernel Hilbert spaces"]', '["Center for Quantum Technologies"]', '[]', '2026-06-23 12:51:24.615', '2026-06-23 12:51:26.127175', '2026-06-23 12:51:24.615', 'Dr. Satish Kumar Pandey earned his Ph.D. in Pure Mathematics in 2018 from University of Waterloo under the supervision of Vern Paulsen. He obtained his MS in Applied Mathematics from University of Houston in 2012. Prior to joining IIIT-Delhi, he was a PBC postdoctoral research fellow in the Faculty of Mathematics at Technion-Israel Institute of Technology (2018-21), working with Orr Shalit. His research interests lie primarily in functional analysis. In particular, he is interested in operator theory (univariate and multivariate), operator algebras, reproducing kernel Hilbert spaces, and quantum information theory (QIT). His research work can be broadly categorized into two parts: operator theory/operator algebras and their techniques in QIT. In addition to these, he is also investigating the application of reproducing kernel Hilbert space techniques in QIT.'),
  ('229', 'Sayak Bhattacharya', 'sayak@iiitd.ac.in', 'Assistant Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/sayakbhatt.jpg', 'Ph.D. (2016), IIT Delhi, India', '011-26907356', 'B-603 (R&D Block)', 'https://www.iiitd.edu.in/~sayak/', 'https://iiitd.ac.in/sayak', '["Ultra-thin and high-efficiency photovoltaics","Strong light-matter interaction in photonic crystals"]', '["Electromagnetics","Photonics","Quantum Optics"]', NULL, '[]', '2026-06-23 12:51:24.909', '2026-06-23 12:51:26.424346', '2026-06-23 12:51:24.909', 'Dr. Sayak Bhattacharya obtained his PhD from Dept. of Electrical Engineering, IIT Delhi in 2016. Before joining IIIT Delhi, he was appointed as a Postdoctoral Fellow in Prof. Sajeev John’s group at the University of Toronto since 2016. His current research focus is light-trapping and energy harvesting in ultra-thin, flexible, silicon photonic crystal solar cells. His broad area of interest is designing semiconductor devices that rely on photonic crystal mediated strong light-matter interaction. He is the recipient of SPIE Best Student Paper Award in the 12th International Conference on Fiber Optics and Photonics, 2014. His paper (co-authored with Prof. John), “Designing High-Efficiency Thin Silicon Solar Cells Using Parabolic-Pore Photonic Crystals", has been featured as Editor’s Suggestion in the April, 2018 issue of Physical Review Applied for illustrating a roadmap towards 28−29% conversion efficiency (well beyond the current world-record efficiency of 26.7%) in silicon solar cells. He has served as a reviewer for Renewable & Sustainable Energy Reviews.'),
  ('230', 'Sayan Basu Roy', 'sayan@iiitd.ac.in', 'Associate Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/sayan.jpg', 'Ph.D. (2019), IIT Delhi, India', '011-26907559', 'A-603 (R&D Block)', 'https://sites.google.com/iiitd.ac.in/dr-sayan-basu-roy/home', 'https://iiitd.ac.in/sayan', '["Adaptive control for uncertain switched systems","Online approximate optimal control using reinforcement learning based solutions","Adaptive backstepping control"]', '["Control Systems","Robotics","Adaptive and Learning Control"]', NULL, '[]', '2026-06-23 12:51:25.218', '2026-06-23 12:51:26.742264', '2026-06-23 12:51:25.218', 'Sayan has obtained his bachelor''s degree in Electronics and Tele-Communication Engineering from Jadavpur University, West Bengal in the year of 2014. Subsequently, he has completed his PhD from the control and automation group of Electrical Engineering at Indian Institute of Technology Delhi (January 2015-February 2019). He is working as an Associate Professor at the Electronics and Communication Engineering Department of Indraprastha Institute of Information Technology Delhi since September 2018. His research on the broad area of nonlinear and adaptive control has got recognition in top-tier journals and conferences of IEEE control systems society. He serves as a reviewer of several reputed journals and conferences including IEEE transactions on Automatic Control, Automatica, IEEE transactions on Neural Network and Learning Systems, International Journal of Adaptive Control and Signal Processing, IEEE Conference on Decision and Control, American Control Conference etc. His current research interest includes adaptive control for uncertain switched systems, online approximate optimal control using reinforcement learning based solutions, adaptive backstepping control and its variants, cooperative control of multi-agent systems, differential games, adaptive extremum seeking control, passivity-based control applications to under-actuated robotics, etc.'),
  ('231', 'Shamik Sarkar', 'shamik@iiitd.ac.in', 'Assistant Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/shamik.jpg', 'Ph.D. (2021), University of Utah', '011-26907453', 'B-412 (R&D Block)', 'https://shamikdesarkar.wixsite.com/shamiksworks', 'https://iiitd.ac.in/shamik', '["Wireless Communication","Spectrum Sharing","Machine Learning"]', '["Computer Networks","Signals and Systems","Communication Systems"]', NULL, '[]', '2026-06-23 12:51:25.521', '2026-06-23 12:51:27.032209', '2026-06-23 12:51:25.521', 'Shamik Sarkar, Ph.D., is a researcher in the area of wireless and mobile networks. He has published several papers in well-known venues, including ACM MobiCom, ACM MobiHoc, ACM IMWUT, IEEE SECON, IEEE TWC, and IEEE TMC. From September 2021 to July 2023, he worked as a postdoctoral scholar in the CORES Lab at the University of California, Los Angeles, where he was advised by Dr. Danijela Cabric. Before that, he obtained his Ph.D. in computer science from the University of Utah, where Dr. Sneha Kumar Kasera advised him. During his Ph.D., Shamik interned for two summers at the Nokia Bell Labs in New Jersey. Before his Ph.D., he worked for three years as a Network Engineer at Cisco Systems, India. He completed his M.Tech in ECE from IIT Roorkee.'),
  ('237', 'Sonal Keshwani', 'sonal.keshwani@iiitd.ac.in', 'Assistant Professor (HCD)', 'HCD', 'https://iiitd.ac.in/sites/default/files/images/faculty/sonal.jpg', 'Ph.D. (2018), Indian Institute of Science, Bangalore.', '011-26907521', 'A-405 (R&D Block)', 'https://www.iiitd.edu.in/~sonal.keshwani/', 'https://iiitd.ac.in/sonal', '["Design Creativity","Biologically Inspired Design","Conceptual Design","Design Methods and Tools"]', '["Human Factors for Design","Interaction Design Perspective Methods","Introduction to HCI"]', NULL, '[]', '2026-06-23 12:51:27.164', '2026-06-23 12:51:28.683964', '2026-06-23 12:51:27.164', 'Sonal Keshwani holds Ph.D. and MSc. degrees in Design from IISc Bangalore (2018) and B.Tech in Production Engineering from G.B. Pant University, Pantnagar (2008).  She is in the review committee of the Journal of Engineering Design, Taylor and Francis, Research in Engineering Design, Springer and ASME IDETIC conference. She has published her work in five reputed international peer-reviewed SCI journals. She was a guest researcher at Japan Advanced Institute of Science and Technology, where she received a prestigious JASSO scholarship. She has international collaborations with Technical University of Denmark, Politecnico-di-Milano, and Ariel University. She was a founding member of the School of Design and Digital Transmedia at DSU Bangalore (2021-2023). She joined IIIT-Delhi as a Visiting Faculty in July 2023. She also has three years of industry experience in Tata Motors Ltd. (2008 – 2011).'),
  ('232', 'Shobha Sundar Ram', 'shobha@iiitd.ac.in', 'Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/shobha.jpg', 'Ph.D. (2009), University of Texas at Austin', '011-26907460', 'B-606 (R&D Block)', 'https://sites.google.com/iiitd.ac.in/shobhasundarram', 'https://iiitd.ac.in/shobha', '["Conceptualize Model Design and Test Electromagnetic Sensors for Following Applications - Through-wall radar sensing of humans","EMI based sensing of energy consumption in buildings, On-chip wireless interconnects"]', '["Antennas and Wave Propagation","Linear Circuits","","Radar Systems","Engineering Electromagnetics"]', NULL, '[]', '2026-06-23 12:51:25.834', '2026-06-23 12:51:27.341798', '2026-06-23 12:51:25.834', '["Shobha Sundar Ram did her Bachelor of Technology in ECE from the University of Madras, India, in 2004, Master of Science and Ph.D. in electrical engineering from the University of Texas at Austin, USA, in 2006 and 2009, respectively. She worked as a research and development electrical engineer at Baker Hughes Inc., USA, from 2009 to 2013. She joined Indraprastha Institute of Information Technology as an Assistant Professor in 2013, where she is currently an Associate Professor in the Department of Electronics and Communications Engineering. She is primarily engaged in research and education, principally in the areas of radar systems and electromagnetic sensor design and modeling. She serves as an Associate Editor for the IEEE Transactions on Aerospace and Electronics Systems, IEEE Transactions on Radar Systems, and is a Guest Editor for IEEE Transactions on Computational Imaging. She has served as a Guest Editor for IET Radar, Sonar, and Navigation and Topics Editor for Frontiers of Signal Processing. She served as the Secretary of the IEEE Microwave Theory and Techniques Society (MTT-S) in 2025.","She is a the Chair of the Young Professionals Standing Committee and a member of the MTT-S Administrative Committee from 2026 to 2028. She is a member of the following technical committees: the Radar System Panel of the IEEE Aerospace and Electronics Systems Society (AESS), the Microwave/mm-Wave Radar, Sensing and Array Systems Technical Committee -24 of MTT-S, and the Sensor Array and Multichannel (SAM) Technical Committee of the IEEE Signal Processing Society (SPS). She is also a member of the following working groups: the Integrated Sensing and Communications Working Groups of MTT-S and AESS, and the Synthetic Aperture Working Group of SPS. She has served in the Technical Program Committee of several international conferences and was the Technical Program Committee Co-Chair of the IEEE Microwave, Antennas, and Propagation Conference (MAPCON) in 2024. She has won several student paper awards for co-authored works in the USA, Europe, and India, and the Qualcomm Innovation Fellowship India award for 2022 and 2024."]'),
  ('233', 'Smriti Singh', 'smriti@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/smriti.jpg', 'Ph.D. (2017), Jawaharlal Nehru University, New Delhi', '011-26907361', 'B-211 (R&D Block)', '#', 'https://iiitd.ac.in/smriti', '["Social Class, Gender, Urban Space and Community","Neo-Urban, Spatial Sociology","Virtual Community and Solidarity","Digital Childhood and Parenting"]', '["Gender and Intersectionality","Social Stratification","Sociology of India","Gender and Media","Sociological Theory","Urban Sociology"]', NULL, '[]', '2026-06-23 12:51:26.137', '2026-06-23 12:51:27.669981', '2026-06-23 12:51:26.137', '["Smriti Singh is an Assistant Professor of Sociology in the Department of Social Sciences and Humanities (SSH). She teaches courses on Gender and Media, Intersectionality Studies, Urban Sociology, Gender and Urban Space, and Sociology of India. Her monograph, The Middle Class in Neo-Urban India: Space, Class and Distinction (Routledge, 2023), examines the socio-spatial formation of the Indian middle class in contemporary urban contexts. She earned her PhD from Jawaharlal Nehru University (JNU), New Delhi in 2017, and was a Fulbright-Nehru Scholar (2015–2016) at University of Michigan, Ann Arbor, Michigan, USA.","Her research interests include urban space, community, identity, gender, and everyday urban life. Alongside peer-reviewed scholarship, she regularly publishes short pieces and sociological commentaries on a wide range of contemporary social and political issues, engaging both academic and public audiences. She has previously taught at Ambedkar University, Delhi; Azim Premji University, Bengaluru; and Lady Shri Ram College for Women, University of Delhi.","She prides herself on being both a learner and an educator. In her free time, she enjoys good coffee, reading and discussing fiction, listening to music, and following political satire and stand-up comedy."]'),
  ('234', 'Sneh Saurabh', 'sneh@iiitd.ac.in', 'Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/sneh.jpg', 'Ph.D. (2012), IIT Delhi, India', '011-26907456', 'B-608 (R&D Block)', 'http://www.iiitd.edu.in/~sneh', 'https://iiitd.ac.in/sneh', '["VLSI Design and Automation","Energy-Efficient Systems","Nanoelectronics","Stochastic Computational Frameworks"]', '["VLSI Design Flow","CAD for VLSI","Semiconductor Devices","Nanoelectronics"]', NULL, '[]', '2026-06-23 12:51:26.443', '2026-06-23 12:51:27.950729', '2026-06-23 12:51:26.443', 'Sneh Saurabh obtained his Ph.D. from IIT Delhi in 2012 and B.Tech. (EE) from IIT Kharagpur in the year 2000. He has rich experience in the semiconductor industry, having spent 16 years working for industry leaders such as Cadence Design Systems, Synopsys India, and Magma Design Automation. He has been involved in developing some of the well-established industry-standard EDA tools for clock synchronization, constraints management, STA, formal verification, and physical design. He has been teaching semiconductor-specific courses since 2016 at IIIT Delhi. His teaching has been rated excellent by students consistently, and he has received the Teaching Excellence award for seven consecutive semesters at IIITD. His current research interests are in the areas of VLSI Design and Automation, Energy-Efficient Systems, and Stochastic Computational Frameworks. He is the author of the books “Introduction to VLSI Design Flow” and “Fundamentals of Tunnel Field-Effect Transistors” and holds three US patents. He is an Editor (IETE Technical Review), an Associate Editor (IEEE Access), a Review Editor (Frontiers in Electronics Integrated Circuits and VLSI), and a Senior Member of IEEE.'),
  ('235', 'Sneha Chaubey', 'sneha@iiitd.ac.in', 'Associate Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/sneha.jpg', 'Ph.D. (2017), University of Illinois at Urbana-Champaign (UIUC)', '011-26907462', 'B-308 (R&D Block)', '#', 'https://iiitd.ac.in/sneha', '["Number theory and its interactions with geometry and dynamics"]', '["Analytic number theory, distribution of sequences and their spacing statistics using level spacing and correlation measures, zeros of Riemann zeta function and L-functions, and exponential sums"]', NULL, '[]', '2026-06-23 12:51:26.659', '2026-06-23 12:51:28.165849', '2026-06-23 12:51:26.659', 'Sneha is PhD from University of Illinois at Urbana-Champaign (UIUC) advised by Prof. Alexandru Zaharescu. She has held Postdoctoral position at the Mathematische Institut, University of Gottingen, Germany. Before joining UIUC she was at NISER, Bhubaneswar where she completed her Integrated BS and MS in mathematics. Her research interests lies in number theory and its interactions with geometry and dynamics. She is especially interested in analytic number theory, distribution of sequences and their spacing statistics using level spacing and correlation measures, zeros of Riemann zeta function and L-functions, and exponential sums.'),
  ('236', 'Soibam Haripriya', 'soibam@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/soibam.jpg', 'Ph.D. (2016), University of Delhi, India', '011-26907360', 'A-204 (R&D Block)', '#', 'https://iiitd.ac.in/soibam', '["Gender, Violence, Northeast India","Poetry and Fiction in Ethnography of Violence","Digital Ethnography"]', '["Gender, Violence, Northeast India","Poetry and Fiction in Ethnography of Violence","Digital Ethnography"]', '["Ethnography Lab","Urban Research Lab"]', '[]', '2026-06-23 12:51:26.887', '2026-06-23 12:51:28.404831', '2026-06-23 12:51:26.887', 'Soibam Haripriya completed her Ph.D from the Department of Sociology, Delhi School of Economics. She was a Fulbright-Nehru Postdoctoral Fellow at the South Asia Institute, University of Texas at Austin (2022-2023). She was also the FWO Postdoctoral Fellow at the Department of Conflict and Development Studies, Ghent University, Belgium and a Fellow at the Indian Institute of Advanced Studies (IIAS), Shimla. She has taught at the Centre for Sociology and Social Anthropology, Tata Institute of Social Sciences (TISS), Guwahati Campus and Gender Studies Programme, School of Human Studies Ambedkar University.'),
  ('238', 'Sonia Baloni Ray', 'sonia@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/sonia.jpg', 'Ph.D. (2012), Georg August University, Goettingen, Germany', '011-26907424', 'B-210 (R&D Block)', 'https://sites.google.com/iiitd.ac.in/soniabaloniray/home', 'https://iiitd.ac.in/sonia', '["Role of attention in visual processing, studying mechanisms of emotion and motion perception"]', '["Attention and Perception","Cognition of Motor movement Computational models of cognition"]', '["Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)"]', '[]', '2026-06-23 12:51:27.404', '2026-06-23 12:51:28.919232', '2026-06-23 12:51:27.404', 'Dr. Sonia Baloni Ray is a Ph.D. degree holder from German Primate Center, Georg August University, Goettingen, Germany in 2012. She did her post-doctoral research at Centre of Behavioural and Cognitive Science, University of Allahabad. During her post-doctoral tenure she received DST-CSRI (Department of Science and Technology, Govt. Of India- Cognitive Science Research Initiative) fellowship. She is interested in studying the mechanisms of attention that are involved in the processing of visual information in our surrounding. She has experience in psychophysics, EEG and eye-tracking methodologies.'),
  ('239', 'Souvik Dutta', 'souvik@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/souvik.jpg', 'Ph.D. (2014), Pennsylvania State University', '011-26907536', 'B-203 (R&D Block)', 'https://sites.google.com/view/souvikdutta/home', 'https://iiitd.ac.in/souvik', '["Political economy, microfinance and economics of digital marketing"]', '["Microeconomics","Political Economy","Development Economics","Information Economics"]', NULL, '[]', '2026-06-23 12:51:27.672', '2026-06-23 12:51:29.183737', '2026-06-23 12:51:27.672', 'Souvik Dutta completed his Ph.D. in Economics from Pennsylvania State University in 2014. He uses both analytical modelling and econometrics in his research. Some of his current areas of interest are in the fields of political economy, microfinance and economics of digital marketing. He has received several research grants from International Growth Centre (IGC), EfD and Centre for Development Economics and Sustainability (CDES). Before his Ph.D, Souvik obtained his masters degree in economics from Delhi School of Economics and his undergraduate degree in economics from Presidency College, Kolkata. Before joining IIIT-D, Souvik was a faculty at Indian Institute of Management, Bangalore.'),
  ('240', 'Sriram K', 'sriramk@iiitd.ac.in', 'Associate Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/sriram.jpg', 'Ph.D. (2004), IIT Madras, India', '011-26907436', 'A-308 (R&D Block)', 'https://sites.google.com/a/iiitd.ac.in/sriram/', 'https://iiitd.ac.in/sriram', '["Systems biology","Cell division cycle","Circadian rhythms","Computational cognitive neuroscience."]', '["Cell biology and Biochemistry","Systems biology","Computational neuroscience."]', NULL, '[]', '2026-06-23 12:51:27.989', '2026-06-23 12:51:29.496153', '2026-06-23 12:51:27.989', 'Sriram got his Ph.D. from IIT-Madras in 2004, and then went on to do his post-doc in various places that includes a two year stint in INRIA, Rocquencourt, France, and at UCSB, USA. His general research interests are systems biology and dynamical system analysis of neuronal models. Presently, he is interested in understanding learning and memory in both Post-traumatic Stress Disorder (PTSD) and depression from systems biology perspective. Besides, his interests also revolves around mathematical modeling of circadian rhythms, cell division cycle, and understanding of biological network dynamics.'),
  ('241', 'Subhashree Mohapatra', 'subhashree@iiitd.ac.in', 'Assistant Professor (Math)', 'Math', 'https://iiitd.ac.in/sites/default/files/images/faculty/subhashreem.jpg', 'Ph.D. (2013), IIT Kanpur, India', '011-26907459', 'A-309 (R&D Block)', '#', 'https://iiitd.ac.in/subhashreem', '["High order schemes for numerical solution of partial differential equations","Optimal control theory","Parallel implementation of computational fluid dynamics related problems"]', '["High order schemes for numerical solution of partial differential equations","Optimal control theory","Parallel implementation of computational fluid dynamics related problems"]', NULL, '[]', '2026-06-23 12:51:28.293', '2026-06-23 12:51:29.804984', '2026-06-23 12:51:28.293', 'Dr. Subhashree Mohapatra obtained her Ph.D. in Applied Mathematics from Indian Institute of Technology Kanpur, India in 2013. Prior to joining IIIT-Delhi, she worked as an Assistant Professor at SRM University A.P., India. She has four years of Post-doctoral experience at IIT Bhubaneswar, IISc. Bangalore (NBHM Post-doctoral fellowship: Spectral element method for Stokes and Navier-Stokes equations), University of Florida, Gainesville (Optimal control theory) and UTHSC San Antonio USA (Software development for PDEs related to Biophysics applications). Her primary research interests include development of high order efficient schemes for numerical solutions of differential equations, their implementation on parallel machines and optimization problems with differential equations as constraints. She has served as a reviewer for the journal IEEE Transactions on Automatic Control.'),
  ('242', 'Sujay Deb', 'sdeb@iiitd.ac.in', 'Professor (ECE, CSE)', 'ECE, CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/sujay.jpg', 'Ph.D. (2012), Washington State University', '011-26907452', 'A-607 (R&D Block)', 'http://faculty.iiitd.ac.in/~sdeb/', 'https://iiitd.ac.in/sdeb', '["Heterogeneous System Architectures (HSA)","SoC Design & Test","Design of novel interconnect architectures for multi-core chips","Hardware Security","Low-cost bio-sensors for preventive healthcare"]', '["Computer Organization","Computer Architecture","SoC Design & Test","Digital VLSI Design"]', '["Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)"]', '[]', '2026-06-23 12:51:28.592', '2026-06-23 12:51:30.10396', '2026-06-23 12:51:28.592', 'Sujay Deb is a Professor in Electronics & Communication Engineering and Computer Science & Engineering at Indraprastha Institute of Information Technology, Delhi (IIIT-D). He received Ph.D. from the School of Electrical Engineering and Computer Science, Washington State University, Pullman, WA on May 2012. Before his current position, he worked as an intern at Intel Labs, Hillsboro, OR. His major awards and achievements include DST INSPIRE Faculty award in 2012; Outstanding Ph.D. student award in Computer Engineering, WSU, 2011; Winner of India-US Grand Challenge Initiative for Affordable Blood Pressure measurement technologies in 2014.'),
  ('252', 'Vibhor Kumar', 'vibhor@iiitd.ac.in', 'Associate Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/vibhork.jpg', 'Ph.D. (2007), Helsinki University of Technology (now Aalto), Finland', '011-26907440', 'A-304 (R&D Block)', 'http://reggen.iiitd.edu.in:1207/People.html', 'https://iiitd.ac.in/vibhork', '["Genomics, Computational Biology and Statistical Signal Processing"]', '["Genomics, Computational Biology and Statistical Signal Processing"]', NULL, '[]', '2026-06-23 12:51:31.154', '2026-06-23 12:51:32.666278', '2026-06-23 12:51:31.154', 'Ph.D. in Computational systems biology, Helsinki University of Technology (now Aalto), Finland. After completing his M. Tech. in computer technology from IIT Delhi, he started working with computational problems of analysing large image datasets from cryoEM and statistical analysis of Genomic data. During his Ph.D., he solved the first and highest resolution (so far) structure of LDL (bad cholesterol) in native state at human body temperature. After completing Ph.D., Dr Vibhor started applying computational approach to genomic data and worked for 1 year at a personal-genomics company in Malaysia. He has worked at Genome Institute of Singapore (GIS) for more than 8 years and has published some fundamental research findings. At GIS he was primarily working on epigenome and gene regulation and applied his findings to other branches such as cancer and stem cell study. Currently he is working in data sciences and Genomics.'),
  ('243', 'Sukanta Nandi', 'sukanta@iiitd.ac.in', 'Assistant Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/sukanta.jpg', 'Ph.D. (2020), Indian Institute of Science, Bangalore, India', '011-26907532', 'B-604 (R&D Block)', 'https://sites.google.com/view/sukantanandi', 'https://iiitd.ac.in/sukanta', '["Light-Matter Interaction, Nanophotonics, Metamaterials, Optoelectronics, Near-Field Microscopy, Infrared Spectroscopy, and Quantum Emitters"]', '["Nano and Metaphotonics (NMP) (ECE567)"]', '["Centre for Quantum Technology (CQT)"]', '[]', '2026-06-23 12:51:28.923', '2026-06-23 12:51:30.428779', '2026-06-23 12:51:28.923', 'Dr. Sukanta Nandi received his MSc (Engg) and Ph.D. from the Indian Institute of Science, Bangalore, India, in December 2020, under the supervision of Prof. Abha Misra. His doctoral research focused on investigating the optoelectronic properties of low-dimensional materials and developing optoelectronic devices. In February 2021, he moved to Israel to pursue postdoctoral research at Bar-Ilan University with Prof. Tomer Lewi, specializing in computational and experimental quantum and nanophotonics. His research interests include-optoelectronics, nanophotonics, single-photon emitters, and metamaterials, with a particular focus on s-SNOM (scattering-type Scanning Near-field Optical Microscopy). He is currently on the editorial board of Microelectronic Engineering (Elsevier) and serves as a reviewer for several international journals, including IOP, AIP, Optica, Wiley, Elsevier, and RSC. His notable achievements include- 2024 Rising Star Award, the KVRSS Young Scientist Research Award in Physics for 2019-2020, Invited Speaker by the European Physical Society, Outstanding Reviewer Award, and being awarded with a gold medal for securing first place in M.Sc. Physics in 2014.'),
  ('244', 'Sumit J Darak', 'sumit@iiitd.ac.in', 'Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/sumit.jpg', 'Ph.D. (2013), Nanyang Technological University (NTU), Singapore', '011-26907427', 'B-605 (R&D Block)', 'http://faculty.iiitd.ac.in/~sumit/', 'https://iiitd.ac.in/sumit', '["Intelligent, Reconfigurable and Self-sustainable wireless radio","Machine learning for wireless networks","Algorithms to architectures"]', '["Green Information and Communication Technology","Advanced digital system design","Advanced digital signal processing"]', NULL, '[]', '2026-06-23 12:51:29.149', '2026-06-23 12:51:30.662986', '2026-06-23 12:51:29.149', '["Sumit J. Darak received his Bachelor''s degree in Electronics and Communication Engineering from Pune University, India, in 2007, and his Ph.D. from the School of Computer Engineering at Nanyang Technological University (NTU), Singapore, in 2013. He is currently a Professor at IIIT-Delhi, India. Prior to joining IIIT-Delhi, he served as a Postdoctoral Researcher at CentraleSupélec, France, from March 2013 to November 2014. His research interests lie in the design of efficient algorithms and their implementation on reconfigurable and intelligent architectures for applications in wireless communication, radar systems, and artificial intelligence (AI). Dr. Darak has contributed to industry through multiple consultancy roles. He worked as a 5G Consultant with VVDN Technologies, India (March 2019 – September 2021), as an SoC Consultant with Apexplus Technologies, India (June 2022 – December 2024), and is currently serving as a Radar System Consultant with Arka Aerospace (since May 2025).","","His research group has received numerous accolades. He is a recipient of the DST INSPIRE Faculty Award (2015–2020), Best Demo Award at CROWNCOM 2016, Second-Best Student Paper Award at IEEE DASC 2017, and the Young Scientist Paper Award at URSI in both 2014 and 2017. He also won the Second-Best Poster Award at COMSNETS 2019, Best Paper Award at AIML Systems 2021, Design Contest Awards at VLSID in 2022 and 2023, the IEEE APCCAS 2024 Design Contest Award, the COMSNETS Best Demo Awards in 2025 and 2026, and the Best Paper Award at IET NCSIPA 2009. From the industry, he has been honored with the National Instruments (NI) Academic Research Grant in 2017 and 2018 and the Qualcomm Innovation Fellowship for three consecutive years—2022, 2023, and 2024. His research has also been supported by grants from DST, DRDO, ANRF and MeiTy. At IIIT-Delhi, Dr. Darak has received Teaching Excellence Awards (2018, 2019, 2020, 2025) and Research Excellence Awards (2021, 2023, 2024, 2025)."]'),
  ('245', 'Supratim Shit', 'supratim@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/supratim.jpg', 'Ph.D. (2021), IIT Gandhinagar, India', '011-26907468', 'B-512 (R&D Block)', 'https://sites.google.com/view/supratims/', 'https://iiitd.ac.in/supratim', '["Randomized Algorithms","Randomized Numerical Linear & Multilinear Algebra","Theoretical & Practical aspects of ML/DL models"]', '["Randomized Algorithms","Randomized Numerical Linear & Multilinear Algebra","Theoretical & Practical aspects of ML/DL models"]', NULL, '[]', '2026-06-23 12:51:29.37', '2026-06-23 12:51:30.878949', '2026-06-23 12:51:29.37', 'Supratim specializes in scaling machine learning and deep learning models using data/model summarization (aka coresets). He earned his PhD from IIT Gandhinagar and previously served as a postdoctoral researcher at the Department of Computer Science, Technion, and the Robotics & Big Data Labs at Haifa University in Israel. His research interests lie in randomized algorithms and the theory and practice of ML/DL models, with a keen focus on solving real-world problems. His current projects are supported by the ANRF under the Ramanujan Fellowship and PMECRG. Outside of his academic pursuits, he enjoys music and traveling.'),
  ('246', 'Syamantak Das', 'syamantak@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/syamantak.jpg', 'Ph.D. (2015), IIT Delhi, India', '011-26907529', 'B-505, (R&D Block)', 'http://faculty.iiitd.ac.in/~syamantak/', 'https://iiitd.ac.in/syamantak', '["Intersection of theoretical computer science and discrete optimization"]', '["Intersection of theoretical computer science and discrete optimization"]', NULL, '[]', '2026-06-23 12:51:29.6', '2026-06-23 12:51:31.106399', '2026-06-23 12:51:29.6', 'Syamantak obtained his Ph.D. from IIT Delhi. He spent 9 months after that as a visiting postdoc at the Max Planck Institute for Informatik, Germany and subsequently another year as a postdoc at the University of Bremen, Germany. His primary research interests lie at the intersection of theoretical computer science and discrete optimization. In particular, he is currently interested in designing approximation and online algorithms for various kinds of combinatorial optimization problems, for example, scheduling, network design.'),
  ('247', 'Tanmoy Kundu', 'tanmoy.kundu@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/tanmoykundu.jpg', 'Ph.D. (2022), IIT kanpur', '011 26907 451', 'A-512 (R&D Block)', 'https://tanmoy1040.wixsite.com/researchprofile', 'https://iiitd.ac.in/tanmoykundu', '["Robot path and task planning","Robot planning under uncertainty","Multi-robot coordination"]', '["Algorithmic Techniques for Robot Planning","Theory of Computation","Operating Systems","Introduction to Programming"]', '["Computer Science and Engineering (CSE)","Infosys Centre for Artificial Intelligence (CAI)"]', '[]', '2026-06-23 12:51:29.859', '2026-06-23 12:51:31.373587', '2026-06-23 12:51:29.859', 'Dr. Tanmoy Kundu was a Postdoctoral Researcher at Technion - Israel Institute of Technology where he worked in the Autonomous Navigation and Perception Lab led by Prof. Vadim Indelman. Tanmoy completed his Ph.D from the department of Computer Science and Engineering, IIT Kanpur, under the supervision of Prof. Indranil Saha. His research interest lies in the areas of robot path and task planning, robot planning under uncertainty, multi-robot coordination. His research led to several publications in top-tier conferences like IROS and ICRA. Prior to joining Ph.D, he did his M.Tech from NIT Tiruchirappalli and B.Tech from West Bengal University of Technology, both the degrees in Computer Science and Engineering. He has three years of work experience in software companies such as SAP Labs India and Cognizant.'),
  ('248', 'Tarini Shankar Ghosh', 'tarini.ghosh@iiitd.ac.in', 'Assistant Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/tarini.jpg', 'Ph.D. (2014), University of Hyderabad, India', '011 26907 375', 'A-312 (R&D Block)', '#', 'https://iiitd.ac.in/tarini', '["Integrated multi-OMICs, metagenome informatics, machine learning and statistical learning"]', NULL, NULL, '[]', '2026-06-23 12:51:30.093', '2026-06-23 12:51:31.608162', '2026-06-23 12:51:30.093', 'Tarini Shankar Ghosh is a computational biologist focusing on human microbiome research. He received his B.Tech from Indian Institute of Technology (IIT) Kharagpur, his M.Tech from IIT Kanpur and his Ph.D from the University of Hyderabad (while working at the TCS Innovation Labs of Tata Consultancy Services Ltd). After completing his PhD, he first worked at the Genome Institute of Singapore (as a post-doctoral researcher) and at the APC Microbiome Ireland at Cork as a senior post-doctoral scientist. He has published more than 50 research papers in notable journals including Nature Medicine, Nature Ecology and Evolution, Gut, Gastroenterology and Nature Reviews Gastroenterology and Hepatology. He is a recipient of the Yakult Young Investigator Award in 2014 and the Torrent ISHR Young Investigator in 2017 and was selected for the Pathway Investigator grant awarded by the Science Foundation Ireland and Irish Research Council. He is also an author of multiple US/EU based patents, primarily pertaining to efficient metagenome-informatics algorithms and identification of putatively therapeutic novel microbial consortia targeting frailty and colorectal cancer.'),
  ('249', 'Tavpritesh Sethi', 'tavpriteshsethi@iiitd.ac.in', 'Professor (CB)', 'CB', 'https://iiitd.ac.in/sites/default/files/images/faculty/dr-tavpritesh.jpg', 'Ph.D. (2014), CSIR-IGIB,', '011 26907 533', 'A-309 (R&D Block)', 'http://tavlab.iiitd.edu.in', 'https://iiitd.ac.in/tavpritesh', '["Big-data for clinical decision support, Machine learning for critical care and community medicine, Human physiology and Teaching Interests are Statistical, Complex networks and machine learning modelling for medicine and biology, Human physiology."]', '["Bridging human physiology and computation for next-generation medicine"]', NULL, '[]', '2026-06-23 12:51:30.315', '2026-06-23 12:51:31.82486', '2026-06-23 12:51:30.315', 'Dr. Tavpritesh Sethi is a Professor in the Department of Computational Biology and the founding head of the Center of Excellence in Healthcare at IIIT-Delhi. His area of expertise lies at the interface of computer science and healthcare. Dr. Sethi received his M.B.B.S from Government Medical College, Amritsar, and Ph.D. from CSIR-Institute of Genomics and Integrative Biology, New Delhi, India. He worked as a research officer at the All India Institute of Medical Sciences, New Delhi, and a CSIR Quick Hire Fellow at CSIR-Fourth Paradigm Institute before joining IIIT-Delhi as a faculty member. He was a visiting faculty at Stanford University for two years in Stanford Medicine''s Department of Biomedical Informatics Research. He is a Sigma Xi Fellow and has been a fellow of the DBT/Wellcome India Alliance and is a Kavli Fellow. His research interests is in integrating social determinants of health into infectious and non-communicable diseases for developing AI solutions. He has developed early warning systems in pediatric and neonatal ICUs and for COVID-19. He is also working on a WHO Alliance-sponsored project on building decision support for Mohalla Clinics using Artificial Intelligence. Dr. Sethi has published more than 50 papers in international journals and serves as an academic editor for PLOS One, Nature Scientific Reports, PeerJ, and the Journal of Genetics. Dr. Sethi is a TEDx speaker and has delivered several keynote addresses at national and international conferences focused on data and AI in healthcare. He serves on the Scientific Advisory Committees of ICMR National Institute of Epidemiology and ICMR National Institute of Occupational Health.'),
  ('250', 'V. Raghava Mutharaju', 'raghava.mutharaju@iiitd.ac.in', 'Associate Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/raghavam.jpg', 'Ph.D. (2016), Wright State University, Dayton, OH, USA', '011-26907455', 'B-404 (R&D Block)', 'http://raghavam.github.io/', 'https://iiitd.ac.in/raghavam', '["Knowledge Graphs/Semantic Web, Ontology modeling and reasoning, Linked Data, Big Data"]', '["Semantic Web, Cloud Computing, Database Systems"]', NULL, '[]', '2026-06-23 12:51:30.641', '2026-06-23 12:51:32.153865', '2026-06-23 12:51:30.641', 'Raghava Mutharaju is an Associate Professor in the Computer Science and Engineering department of IIIT-Delhi, India and leads the Knowledgeable Computing and Reasoning (KRaCR; pronounced as cracker) Lab. He got his Ph.D. in Computer Science and Engineering from Wright State University, Dayton, OH, USA, in 2016. He has worked in Industry research labs such as GE Research, IBM Research, Bell Labs, and Xerox Research. His research interest is in Semantic Web and in general in Knowledge Representation and Reasoning. This includes knowledge graphs, ontology modelling, reasoning, querying, and its applications. He has published at several venues such as ISWC, ESWC, ECAI, and WISE. He has co-organized workshops at ISWC 2020, WWW 2019, WebSci 2017, ISWC 2015 and tutorials at ISWC 2019, IJCAI 2016, AAAI 2015 and ISWC 2014. He is/has been on the Program Committee of several (Semantic) Web conferences such as AAAI, WWW, ISWC, ESWC, CIKM, K-CAP and SEMANTiCS. More information is available on his lab''s homepage athttps://kracr.iiitd.edu.in.'),
  ('251', 'Venkata Ratnadeep Suri', 'ratan.suri@iiitd.ac.in', 'Assistant Professor (SSH)', 'SSH', 'https://iiitd.ac.in/sites/default/files/images/faculty/ratna-suri.jpg', 'Ph.D. (2013), Indiana University, Bloomington, Indiana', '011-26907445', 'B-204 (R&D Block)', '#', 'https://iiitd.ac.in/ratan', '["ICTs and Society, Information Literacy, Data Literacy, E-Health, M-health, Social media for Health, ICTs and Health behavior, ICTs and Development."]', '["Social Sciences"]', '["Center for Design and New Media (Supported by Tata Consultancy Services, a TCS Foundation Initiative)"]', '[]', '2026-06-23 12:51:30.928', '2026-06-23 12:51:32.434983', '2026-06-23 12:51:30.928', 'Ratnadeep Suri (Ratan), Assistant Professor, SSH, IIIT-Delhi, has completed his Post Doctoral research at the Nanyang Technological University, Singapore in 2016. Earlier he earned his PhD from The Indiana Media School, Indiana University in 2013, with a Major in Communication and a Minor in Information Science. He also has an MA from Western Michigan University, Michigan, and an MA from University of Hyderabad, India. His research examines the effects of technology use in knowledge work contexts, health contexts, information seeking, and the cognition of information. He is also interested in the consequences of disrupted access to communication technologies on individuals in disadvantaged communities. Currently he is a Collaborating Investigator for a 100, 000 $SG grant from Singapore Ministry of Education. He was the recipient of several awards including the the Indiana University, College of Arts and Sciences Dissertation Fellowship (2010-2011), The Indiana University Future Faculty Fellowship, to teach at Howard University, 2009-2010, The Graduate School Fellowship, Summer 2004, 2005, Indiana University, and The Kellogg Foundation Service Learning Scholarship in Summer 2002. In his free time Ratan pursues his interests in woodworking, traveling and photography.'),
  ('253', 'Vikram Goyal', 'vikram@iiitd.ac.in', 'Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/vikram.jpg', 'Ph.D. (2009), IIT Delhi, India', '011-26907474', 'A-508 (R&D Block)', 'http://faculty.iiitd.ac.in/~vikram/', 'https://iiitd.ac.in/vikram', '["Data Mining","Databases","Spatial Data Analytics"]', '["Databases","Data Mining","Algorithms for Spatial Query Evaluation"]', '["Infosys Centre for Artificial Intelligence (CAI)"]', '[]', '2026-06-23 12:51:31.371', '2026-06-23 12:51:32.890807', '2026-06-23 12:51:31.371', '["Dr. Vikram Goyal is a professor in the Department of Computer Science and Engineering at IIIT Delhi. He is also a member of the Infosys Center of Artificial Intelligence at IIIT Delhi.","He joined IIIT Delhi in 2008, and before that, he did his Ph.D. and M.Tech. from IIT Delhi and NSUT Delhi, respectively. His primary research focus is Data Science and Big Data Analytics. He has completed several Govt. funded and Consultancy projects at IIIT Delhi. He and his colleagues got a Technology Innovation Hub project from the DST worth Rs. 100 crores for technology and research in Cognitive computing and social sensing. He has supervised many Ph.D. students and guiding several others currently. He has also advised several MTech and BTech students on their projects. His work got published at top-tier Computer Science conferences and journals, including NAACL, ICDE, WSDM, TIST, ECML PKDD, and ECIR. He has co-chaired a committee that designed the CBSE''s K-12 Coumpter Science courses curriculum."]'),
  ('254', 'Vinayak Abrol', 'abrol@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/vabrol.jpg', 'Ph.D. (2018), IIT Mandi, India', '011-26907543', 'B-409 (R&D Block)', 'https://sites.google.com/view/vinayakabrol/home', 'https://iiitd.ac.in/vabrol', '["Acoustic modelling and coding","Voice biometrics","Pathological speech and audio categorization"]', '["Theories of Deep Learning","Machine Learning","Speech and Audio Processing"]', NULL, '[]', '2026-06-23 12:51:31.665', '2026-06-23 12:51:33.179675', '2026-06-23 12:51:31.665', 'Vinayak Abrol is an Assistant Professor at IIIT-Delhi and a faculty member specializing in Machine Learning and Deep Learning. His academic journey includes a TCS Innovation Labs funded Ph.D. from IIT Mandi, followed by prestigious roles such as an Oxford-Emirates data science fellow at the University of Oxford and a postdoctoral researcher at the IDIAP Research Institute in Switzerland. His research focuses on the design, and analysis of numerical algorithms for information inspired applications, which is multi-disciplinary and lies at an intersection of Engineering, Maths and Computer Science. On the theoretical front he is currently working on developing theories of deep learning using tools from random matrix theory, and information theory, where as on the applied front his research interest is in area of speech/audio analytics on problem such as SpeechLMs, acoustic modelling and coding, voice biometrics, and audio categorization.'),
  ('255', 'Vivek Bohara', 'vivek.b@iiitd.ac.in', 'Professor (ECE)', 'ECE', 'https://iiitd.ac.in/sites/default/files/images/faculty/vivek.jpg', 'Ph.D. (2011),  Nanyang Technological University, Singapore', '011-26907454', 'A-609 (R&D Block)', 'https://sites.google.com/a/iiitd.ac.in/vivek-ashok-bohara/', 'https://iiitd.ac.in/vivek', '["Visible Light Communication (Li-FI )","Cyber physical systems","Optical Intelligent Reflective surfaces","UAV and vehicular communication"]', '["Wireless Communication","Digital Communication and Wireless System Implementation"]', '["Centre of Excellence on Light Fidelity (LiFi)","Wirocomm Research Group"]', '[]', '2026-06-23 12:51:31.973', '2026-06-23 12:51:33.49021', '2026-06-23 12:51:31.973', '["Dr. Vivek Ashok Bohara received the Ph.D. degree from Nanyang Technological University, Singapore, in 2011. From 2011 to 2013, he was a Postdoctoral Researcher (Marie Curie fellowship) in ESIEE Paris, University Paris-East where he was actively involved in designing and implementing critical blocks for wideband RF transmitters. Specifically, he proposed numerous green communication techniques to reduce power consumption and increase efficiency of nonlinear high power amplifiers used in RF transmitters.","In 2013, he joined IIIT-Delhi, India, where he is currently Professor (ECE) and Dean (Innovation, research and Development). He has authored and coauthored over 200 publications in major IEEE journals and refereed international conferences, three book chapters, and seven patents. Dr. Bohara also supervises the Wirocomm Research Lab at IIIT Delhi which deals with state of the art research in wireless communication and allied area and is also the co-founding faculty member for Li-Fi Centre of excellence @ IIIT-Delhi. His research interests are next-generation communication technologies such as Visible Light Communication (VLC), hybrid RF-VLC communication, integration of optical communication with intelligent reflective surfaces (IRS), UAV, and vehicular communication.","Dr. Bohara received First Prize in National Instruments ASEAN Virtual Instrumentation Applications Contest in 2007 and 2010. He was also the recipient of the Best Paper Award at the IEEE ANTS and the best poster and demo awards at IEEE Comsnets conferences respectively. From March 2023 till Feb 2024 Dr. Bohara was also a recipient of TIH-IoT CHANAKYA Faculty Fellowship from the TiH Foundation at IIT Bombay. Dr. Bohara also offers multiple NPTEL Swayam courses in Hindi language in the broad areas of wireless communications and 6G."]'),
  ('256', 'Vivek Kumar', 'vivekk@iiitd.ac.in', 'Assistant Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/vivekk.jpg', 'Ph.D. (2014), Research School of Computer Science, Australian National University', '011-26907441', 'B-506 (R&D Block)', 'http://vivkumar.github.io', 'https://iiitd.ac.in/vivekk', '["Parallel programming models and runtime systems."]', '["Parallel programming models and runtime systems."]', NULL, '[]', '2026-06-23 12:51:32.279', '2026-06-23 12:51:33.791115', '2026-06-23 12:51:32.279', 'Vivek Kumar works in the field of High-Performance Computing (HPC). He received his Ph.D. from the Australian National University in 2014. His doctoral research focused on using managed runtime techniques to improve the performance and productivity of parallel programming on multicore architectures. Prior to his Ph.D., he worked for nearly six years in research and development positions within the HPC sector at C-DAC R&D and IBM Systems and Technology Labs. After completing his doctorate, he spent nearly three years as a Research Scientist at Rice University. His current research focuses on designing runtime techniques to achieve high performance and energy efficiency on multicore processors, GPUs, and SoCs.'),
  ('257', 'Pankaj Jalote', 'jalote@iiitd.ac.in', 'Emeritus Professor (CSE)', 'CSE', 'https://iiitd.ac.in/sites/default/files/images/faculty/jalote.jpg', 'Ph.D. (1985), University of Illinois at Urbana Champaign, USA', '011-26907499', 'A-705 (R&D Block)', 'http://faculty.iiitd.ac.in/~jalote/', 'https://iiitd.ac.in/jalote', '["Software quality, process improvement","Higher Education in India"]', '["Software Engineering, Quantitative Methods in Software Engineering","E-Commerce, Effective Teaching, Technical Communication."]', NULL, '[]', '2026-06-23 12:51:32.502', '2026-06-23 12:51:34.009728', '2026-06-23 12:51:32.502', '["Pankaj Jalote is currently an Emeritus Professor (CSE). He was the founding Director of IIIT-Delhi from 2008 to 2018. Earlier, he has also been an Assistant Professor at the University of Maryland, College Park, Professor and Head of the Computer Science Department at IIT Kanpur, and Chair Professor at IIT Delhi. He has also been Vice President at Infosys for 2 years, a Visiting Researcher at Microsoft in Redmond for 1 year, and an Interim Vice Chancellor of Delhi Technological University (DTU) for 6 months. He has a B.Tech. from IIT Kanpur, an MS from Pennsylvania State University, and a Ph.D. from the University of Illinois at Urbana-Champaign. He is the author of five books, some of which have been translated into Chinese, Japanese, Korean, and other languages, and the Indian edition of his text on Software Engineering was adjudged the bestselling book by the publisher. His main area of interest is Software Engineering and Higher Education. He has served on the editorial boards of IEEE Transactions on Software Engineering, Intl. Journal on Empirical Software Engineering, and IEEE Trans. on Services Computing. He is a Fellow of the IEEE and INAE."]')
;

COMMIT;
